// Banco de frases — German
// Generado automáticamente desde frases.js
export const FRASES_DE = [
  {t:"Ihre Fantasie ist kein Luxus oder eine Flucht. Es ist die einzige Werkstatt, in der die Zukunft gebaut wird, bevor sie existiert.", a:null},
  {t:"Was Sie draußen erleben, entspricht genau dem, was Sie drinnen für möglich gehalten haben. Wenn Sie die Welt verändern wollen, ändern Sie zuerst die Welt, die Sie im Kopf haben.", a:null},
  {t:"Neville Goddard hat es mit chirurgischer Präzision gesagt: Stellen Sie sich nicht vor, was Sie wollen, sondern stellen Sie sich das vor, wo Sie es bereits haben.", a:"N. Goddard"},
  {t:"Der Geist, der auf Beweise wartet, bevor er glaubt, wird sie niemals erhalten. Der Geist, der glaubt, bevor er Beweise sieht, ist der Einzige, der sie letztendlich berührt.", a:null},
  {t:"Dein Gewissen registriert nicht, was passiert. Notieren Sie, was Ihrer Meinung nach passiert. Dieser Unterschied ist alles.", a:null},
  {t:"Jeder emotionale Zustand, in dem Sie sich regelmäßig befinden, wird zu einer Anweisung, die Ihre Realität nicht ignorieren kann.", a:null},
  {t:"Es gibt keine Lücke zwischen dem, was Sie sich mit voller Überzeugung vorstellen, und dem, was sich letztendlich manifestiert. Es dauert nur so lange, bis Sie es vollständig glauben.", a:null},
  {t:"Die Frage ist nicht: „Kann ich es erreichen?“ Die Frage ist: „Kann ich an dem Bild festhalten, dass ich es lange genug erreicht habe, damit es Wirklichkeit wird?“", a:null},
  {t:"Sie leben in dem Zustand, den Sie für wahr halten. Niemand sonst zwingt es dir auf. Das ist erschreckend und befreiend zugleich.", a:null},
  {t:"Die meisten Menschen stellen sich vor, was sie fürchten. Die wenigen, die die Welt verändern, stellen sich vor, was sie lieben.", a:null},
  {t:"Ihr Unterbewusstsein unterscheidet nicht zwischen dem, was Sie erlebt haben, und dem, was Sie sich mit echten Emotionen vorgestellt haben. Das ist Ihr größtes Werkzeug und Ihre größte Verantwortung.", a:null},
  {t:"Die Tatsache, dass Sie sich deutlich etwas vorstellen können, was noch nicht existiert, ist ein Beweis dafür, dass auf einer Ebene bereits etwas existiert, das Sie noch nicht sehen konnten.", a:null},
  {t:"Wenn Sie aufhören, die aktuelle Realität um Erlaubnis zu bitten, sich eine andere vorzustellen, beginnen Sie, frei zu sein.", a:null},
  {t:"Es gibt nichts Praktischeres, als zu verstehen, dass die physische Welt der letzte Ort ist, an dem Veränderungen stattfinden, und nicht der erste.", a:null},
  {t:"Was Sie über sich selbst annehmen, ist am Ende meist wahrer als alle externen Beweise, die Ihnen widersprechen.", a:null},
  {t:"Der emotionale Zustand, in dem Sie einschlafen, ist die letzte Anweisung, die Sie Ihrem Geist geben, bevor er beginnt, an der Gestaltung Ihrer Zukunft zu arbeiten.", a:"A.DSL"},
  {t:"Stellen Sie sich das Ergebnis so vor, als ob der Weg bereits zurückgelegt worden wäre, verbinden Sie sich und leben Sie in einer Schwingung des Erfolgs. Ihr Nervensystem weiß nicht, dass es nicht wahr ist.", a:null},
  {t:"Der Unterschied zwischen denen, die träumen, und denen, die etwas erreichen, ist nicht Talent. Es ist die Bereitschaft, das Ergebnis emotional zu erleben, bevor es physisch zum Vorschein kommt.", a:null},
  {t:"Jedes Mal, wenn Sie sich Ihr Leben so vorstellen, wie Sie es sich wünschen, und es in Ihrem Körper real spüren, säen Sie mit dem mächtigsten Werkzeug, das es gibt.", a:null},
  {t:"Die Vergangenheit hat nur die Macht, die du ihr in diesem Moment gibst. Der Geist, der es immer wieder durchlebt, entscheidet sich dafür, dass es präsent bleibt.", a:null},
  {t:"Napoleon Hill hat es allen vermittelt: Ein brennendes, definiertes Verlangen ist kein schöner Ausgangspunkt. Es ist der Kraftstoff, ohne den kein Motor startet.", a:"N. Hill"},
  {t:"Glaube bedeutet nicht, dass alles gut ausgehen wird. Es bedeutet zu wissen, dass man die Fähigkeit hat, auf alles zu reagieren, was nicht gut läuft.", a:null},
  {t:"Das Universum belohnt leere Anstrengungen nicht. Es belohnt Bemühungen, die auf einer Überzeugung beruhen, die nicht verhandelt.", a:null},
  {t:"Beharrlichkeit ist kein Eigensinn. Es ist die bewusste Entscheidung, das Ergebnis nicht von Zeit oder Schwierigkeit bestimmen zu lassen.", a:null},
  {t:"Es gibt etwas in der menschlichen Natur, das nur dann aktiviert wird, wenn die Person ohne Möglichkeit einer Rückkehr entscheidet, dass das, was sie will, bereits ihnen gehört.", a:null},
  {t:"Zweifel sind nicht das Problem. Das Problem ist, dass Sie Zweifeln das gleiche Gewicht beimessen wie Ihrer Überzeugung. Sie haben nicht den gleichen Wert.", a:null},
  {t:"Jede große Erfolgsgeschichte, die Sie kennen, hat irgendwann ein Kapitel, das niemand gesehen hat: das der Person, die allein, erschöpft und immer noch entschlossen ist, daran zu glauben.", a:null},
  {t:"Fragen Sie die Angst nicht, ob Sie es versuchen können. Angst wird immer Nein sagen. Fragen Sie die Version von Ihnen, die es bereits geschafft hat.", a:null},
  {t:"Was am schwierigsten aufrechtzuerhalten ist, ist nicht der Job. Es ist Glaube, wenn die Arbeit noch keine sichtbaren Früchte getragen hat.", a:null},
  {t:"Napoleon Hill beobachtete bei 500 erfolgreichen Menschen eine Konstante: Sie alle hatten einen Moment, in dem ihnen die ganze Welt sagte, dass sie falsch lagen, und sie blieben die gleichen.", a:"N. Hill"},
  {t:"Scheitern hat nur eine nützliche Funktion: Ihnen genau zu zeigen, welchen Teil des Weges Sie noch nicht verstehen.", a:null},
  {t:"Die Sicherheit, die Sie im Außen suchen, wird niemals so solide sein wie die, die Sie im Inneren aufbauen. Draußen kann sich alles ändern. Im Inneren bist du nur auf dich selbst angewiesen.", a:null},
  {t:"Es gibt Menschen, die sich seit Jahren auf den Moment vorbereiten, der bereits gekommen ist. Eine perfekte Vorbereitung gibt es nicht. Der Moment ja.", a:null},
  {t:"Das Problem beim Warten darauf, „bereit zu sein“, besteht darin, dass die eigentliche Vorbereitung erst auf dem Spielfeld stattfindet und nicht, bevor man es betritt.", a:null},
  {t:"Bei Resilienz geht es nicht darum, nicht zu fallen. Man ist oft genug gefallen, um mit Sicherheit zu wissen, dass man immer wieder aufgestanden ist.", a:null},
  {t:"Alles, was Sie begonnen und aufgegeben haben, weil es schwierig war, hat Ihnen eine Schuld bei sich selbst hinterlassen. Heute können Sie mit der Rückzahlung beginnen.", a:null},
  {t:"Aktiver Glaube ist nicht passiv. Sie ist diejenige, die um 6 Uhr morgens aufsteht und arbeitet, als ob das Ergebnis bereits garantiert wäre.", a:null},
  {t:"Echtes Verlangen hat eine Eigenschaft, die es von der Laune unterscheidet: Es erschöpft sich nicht durch die erste Schwierigkeit.", a:null},
  {t:"Jedes Mal, wenn Sie sich dafür entscheiden, es ohne große Chance zu versuchen, senden Sie Ihrem Nervensystem die stärkste Botschaft, die es gibt: „Ich bin jemand, der nicht aufgibt.“", a:null},
  {t:"Es ist physikalisch unmöglich, dass eine Idee, die lange genug mit echten Emotionen festgehalten wird, nicht in irgendeiner Form verwirklicht wird.", a:null},
  {t:"Nicht jede Anstrengung führt zu sofortigen Ergebnissen. Aber jede Anstrengung bringt etwas hervor: die Person, die du sein kannst.", a:null},
  {t:"Es gibt Samen, deren Keimung Jahre dauert. Was von außen wie Inaktivität aussieht, kann von innen heraus eine tiefgreifende Vorbereitung sein.", a:null},
  {t:"Wille ist nicht die Abwesenheit des Wunsches, sich zu ergeben. Es ist die Gewohnheit, trotz dieses Wunsches weiterzumachen.", a:null},
  {t:"Jede außergewöhnliche Leistung hat gewöhnliche Wurzeln: eine Entscheidung, die in einem gewöhnlichen Moment getroffen und auf außergewöhnliche Weise aufrechterhalten wird.", a:null},
  {t:"Jim Rohn bemerkte es kühl: Sein Leben nicht zu gestalten bedeutet, es trotzdem zu gestalten. Nur das Design wird von anderen gemacht.", a:"J. Rohn"},
  {t:"Disziplin ist keine Willenskraft. Es ist das System, das Sie aufbauen, damit der Wille nicht so hart arbeiten muss.", a:null},
  {t:"Der Typ Mensch, der Sie in fünf Jahren sein möchten, basiert auf den kleinen Entscheidungen von heute, die niemand sieht und die niemand belohnt.", a:null},
  {t:"Was Sie im Stillen wiederholen, wenn niemand hinschaut, ist letztendlich Ihr Charakter.", a:null},
  {t:"An sich selbst zu arbeiten ist kein Egoismus. Es ist die einzige Investition, die Ihnen niemand mehr nehmen kann und die sich in allen Bereichen gleichzeitig auszahlt.", a:null},
  {t:"Es gibt einen großen Unterschied zwischen beschäftigt und produktiv sein. Geschäftigkeit ohne Richtung ist Energie, die für den Anschein von Fortschritt aufgewendet wird.", a:null},
  {t:"Die Mehrheit lebt davon, zu reagieren. Wer sein Leben gestaltet, hat gelernt, darauf zu reagieren. Der Unterschied liegt in der Pause zwischen Reiz und Handlung.", a:null},
  {t:"Es ist nicht Talent, das Menschen trennt. Es ist die Bereitschaft zu arbeiten, wenn das Talent nicht ausreicht.", a:null},
  {t:"Die Ergebnisse, die Sie heute erhalten, sind die genaue Zusammenfassung der Entscheidungen, die Sie in der Vergangenheit getroffen haben. Die heutigen Entscheidungen schreiben das Resümee der Zukunft.", a:null},
  {t:"Die Gewohnheit fragt Sie nicht, wie es Ihnen geht, wenn es Zeit ist, sie auszuführen. Deshalb gewinnt die Gewohnheit, wo die Motivation immer verliert.", a:null},
  {t:"Jim Rohn sagte, dass Erfolg nicht angestrebt wird. Es zieht Sie an, weil Sie zu dem Typ Mensch werden, der es verdient, erfolgreich zu sein.", a:"J. Rohn"},
  {t:"Das Leben verbessert sich nicht durch Zufall oder durch Warten. Verbessert durch die Anhäufung bewusster Entscheidungen, die zu Zeiten getroffen wurden, in denen es einfacher war, sie nicht zu treffen.", a:null},
  {t:"Es gibt Menschen, die mehr Zeit verlangen, und es gibt Menschen, die das, was sie haben, besser nutzen. Die Uhr ist bei beiden gleich.", a:null},
  {t:"Klarheit darüber, was Sie wollen, ist an sich schon eine Form der Arbeit. Unbestimmtheit führt ausnahmslos zu vagen Ergebnissen.", a:null},
  {t:"Der Standard, den Sie für sich selbst akzeptieren, bestimmt absolut alles, was Sie bekommen, auch wenn ihn sonst niemand sieht.", a:null},
  {t:"Etwas Wertvolles aufzubauen sieht von außen immer wie das Gleiche aus: eine Person, die etwas Alltägliches mit außergewöhnlicher Konsequenz tut.", a:null},
  {t:"Die Qualität Ihrer privaten Gedanken, die Sie niemandem erzählen, bestimmt die Qualität Ihres öffentlichen Lebens.", a:null},
  {t:"Unterschätzen Sie nicht die Kraft einer einzigen Stunde am Tag, die Sie dem Wachstum widmen. In einem Jahr gibt es mehr als 300 Stunden Vorteil, die die meisten nie haben werden.", a:null},
  {t:"Echtes Wachstum fühlt sich fast nie wie Wachstum an, solange es stattfindet. Es ist eher Anstrengung, Unbehagen und Zweifel.", a:null},
  {t:"Was Sie als „keine Zeit haben“ bezeichnen, bedeutet fast immer, dass Sie „noch nicht entschieden haben, dass dies eine Priorität ist“.", a:null},
  {t:"Ihr Unterbewusstsein argumentiert oder argumentiert nicht. Akzeptieren Sie das, was Sie mit Emotion und Konsequenz wiederholen, als wahr.", a:null},
  {t:"Überfluss ist kein wirtschaftlicher Zustand. Es ist zunächst ein Bewusstseinszustand und erst dann eine materielle Realität.", a:null},
  {t:"Was Sie als „Pech“ oder „Pech“ erleben, hat fast immer seine Wurzeln in einem Gedankenmuster, das Sie identifizieren und ändern können.", a:null},
  {t:"Die wirkliche Grenze dessen, was Sie in diesem Leben erhalten können, ist fast immer die Grenze dessen, was Sie Ihrer Meinung nach verdienen.", a:null},
  {t:"Es gibt Menschen, die unermüdlich arbeiten und keinen Überfluss erreichen, und Menschen, die mit emotionaler Intelligenz arbeiten und diese anziehen. Der Unterschied liegt im inneren Zustand, von dem aus sie handeln.", a:null},
  {t:"Was Sie vor dem Schlafengehen und nach dem Aufwachen mental wiederholen, ist das, was Sie am stärksten programmieren. Wählen Sie es sorgfältig aus.", a:null},
  {t:"Wohlstand ist nicht das, was man anhäuft. Es ist die Fähigkeit, dort Werte zu schaffen, wo man hingeht, und Chancen zu erkennen, die andere nicht sehen.", a:null},
  {t:"Wenn das Bewusstsein und das Unterbewusstsein in die gleiche Richtung weisen, wird die Anstrengung zum Fluss und die Arbeit wird weniger belastend.", a:null},
  {t:"Die Überzeugungen über Geld, Erfolg und Wert, die Sie vor Ihrem siebten Lebensjahr angenommen haben, bestimmen immer noch Ihre Entscheidungen als Erwachsener, es sei denn, Sie haben sie bewusst revidiert.", a:null},
  {t:"Sie können nicht empfangen, was Ihrer inneren Meinung nach nicht Ihnen gehört. Die häufigste Ablehnung kommt nicht von außen.", a:null},
  {t:"Echte Dankbarkeit ist keine optionale spirituelle Praxis. Es ist der emotionale Zustand, der Ihr System auf die Möglichkeit einstimmt, mehr zu empfangen.", a:null},
  {t:"Ihre Beziehung zu Geld ist die gleiche wie die, die Sie zu sich selbst haben. Ändere das eine und ändere das andere.", a:null},
  {t:"Der Fluss an Möglichkeiten in Ihrem Leben ist proportional zum Wertfluss, den Sie generieren, ohne die Rendite in jedem Moment zu berechnen.", a:null},
  {t:"Was Sie als Obergrenze dessen betrachten, was Sie erreichen können, ist fast immer die Untergrenze dessen, was jemand anderes bereits mit weniger Ressourcen als Sie erreicht hat.", a:null},
  {t:"Viktor Frankl hat die Konzentrationslager überlebt und ist zu dem Schluss gekommen: Das Einzige, was man einem nicht nehmen kann, ist die Haltung, die man wählt, wenn man mit dem konfrontiert wird, was einem widerfährt.", a:"V. Frankl"},
  {t:"Zwischen dem, was dir passiert, und dem, was du damit machst, gibt es einen Raum. In diesem Raum liegt all deine Freiheit.", a:null},
  {t:"Die Person, die Sie vor fünf Jahren waren, traf Entscheidungen anhand der Informationen, die Sie hatten. Es aus heutiger Sicht zu beurteilen, ist nicht klug. Es ist Grausamkeit, die als Reflexion getarnt ist.", a:null},
  {t:"Es gibt einen Unterschied zwischen dem Akzeptieren dessen, was ist, und der Resignation mit dem, was sein wird. Akzeptanz ist der Ausgangspunkt einer echten Veränderung. Der Rücktritt ist sein Ende.", a:null},
  {t:"Niemand erreicht ein wichtiges Ziel, ohne tief daran gezweifelt zu haben, ob er dorthin gelangen kann. Zweifel sind Teil der Reise und kein Zeichen dafür, dass Sie auf dem falschen Weg sind.", a:null},
  {t:"Was Sie an anderen zutiefst stört, ist meist der Spiegel von etwas, das Sie noch nicht in sich integriert haben.", a:null},
  {t:"Du kannst im ersten Moment nicht kontrollieren, was du denkst. Ja, Sie können steuern, welchen Gedanken Sie Nahrung und Zeit widmen.", a:null},
  {t:"Reife ist nicht die Abwesenheit schwieriger Emotionen. Es ist die Fähigkeit, sie zu spüren, ohne dass sie Ihre Entscheidungen diktieren.", a:null},
  {t:"Jeder Mensch, dem man begegnet, trägt eine Last, die man nicht immer sieht. Das rechtfertigt nicht alles, was sie tun, aber es macht es einfacher, es nicht persönlich zu nehmen.", a:null},
  {t:"Es gibt Momente im Leben, die erst im Nachhinein verstanden werden. Während man sie lebt, scheinen sie Hindernisse zu sein. Sie werden dann als Vorbereitung offenbart.", a:null},
  {t:"Komfort ist nicht der Feind. Der Trost, der mit dem Schicksal verwechselt wird, ist.", a:null},
  {t:"Es gibt Leute, die 40 Jahre Erfahrung haben, und Leute, die ein Jahr Erfahrung 40 Mal wiederholt haben. Der Unterschied besteht darin, ob sie aus dem, was sie erlebt haben, gelernt haben.", a:null},
  {t:"Was Sie vermeiden, verschwindet nicht. Warte ruhig und wachse.", a:null},
  {t:"Es war nicht nur verschwendete Zeit. Manche Dinge müssen reifen, bevor sie erscheinen können.", a:null},
  {t:"Eine wirkliche Veränderung findet nicht statt, wenn sich die Umgebung ändert. Es passiert, wenn die Person, die diese Umgebung bewohnte, nicht mehr dieselbe ist.", a:null},
  {t:"Es gibt Fragen, auf die es noch keine Antworten gibt. Zu lernen, mit dieser Unsicherheit bequem zu leben, ist eine der wertvollsten Fähigkeiten, die es gibt.", a:null},
  {t:"Was wir „Glück“ nennen, ist normalerweise die Schnittstelle zwischen der Vorbereitung, die Sie getroffen haben, als niemand zusah, und der Gelegenheit, die sich bot, als Sie es am wenigsten erwartet hatten.", a:null},
  {t:"Jede Entscheidung, die Sie in Ihrem besten Zustand treffen, schafft den Weg. Jede Entscheidung, die Sie in Ihrem schlimmsten Zustand treffen, verursacht Lärm auf der Straße.", a:null},
  {t:"Der Unterschied zwischen einer Krise und einem Übergang besteht darin, ob Ihre Identität die Veränderung überlebt oder sich durch sie verändert.", a:null},
  {t:"Es ist hilfreich, sich zu fragen, was passieren würde, wenn Sie scheitern würden. Dringender ist die Frage, was passieren würde, wenn man es nicht versucht.", a:null},
  {t:"Was Sie stillschweigend tolerieren, setzt den Maßstab dafür, was das Leben Ihnen weiterhin bieten wird.", a:null},
  {t:"Es gibt Menschen, die sich nicht ändern, nicht weil sie es nicht können, sondern weil Veränderung bedeutet, zuzugeben, dass sie falsch lagen, und das erscheint ihnen teurer, als gleich zu bleiben.", a:null},
  {t:"Die Zeit, die Sie damit verbringen, sich wie ein Opfer Ihrer Geschichte zu fühlen, ist Zeit, die Sie nicht nutzen, um das nächste Kapitel zu schreiben.", a:null},
  {t:"Das Leben ist in der Verteilung der Lasten selten gerecht. Ja, es ist, oft überraschend, in der Verteilung der Möglichkeiten für diejenigen, die sie zu sehen wissen.", a:null},
  {t:"Wie viele Jahre haben Sie etwas aufgeschoben, das, wenn Sie es täten, alles andere verändern würde?", a:null},
  {t:"Was würden Sie heute tun, wenn Sie niemandem etwas beweisen müssten?", a:null},
  {t:"Ist die Geschichte, die Sie sich selbst darüber erzählen, warum Sie es nicht schaffen, eine Beschreibung der Realität oder eine als Beschreibung getarnte Entscheidung?", a:null},
  {t:"Welchen Rat würden Sie jemandem in Ihrer genauen Situation geben? Warum gibst du es dir nicht selbst?", a:null},
  {t:"Was muss passieren, damit Sie nicht mehr auf den perfekten Moment warten und anfangen können?", a:null},
  {t:"Wie oft hat sich die Angst, die Sie jetzt haben, als größer erwiesen, als sie wirklich war?", a:null},
  {t:"Welchen Teil Ihres aktuellen Lebens haben Sie bewusst konstruiert und welcher Teil ist einfach passiert, während Sie zugeschaut haben?", a:null},
  {t:"Sind Sie mit dem Dringenden beschäftigt oder treiben Sie das Wichtige voran? Wann haben Sie diesen Unterschied das letzte Mal überprüft?", a:null},
  {t:"Was würden Sie weiterhin tun, wenn Sie sicher wüssten, dass Ihnen niemand applaudieren oder Sie anerkennen würde?", a:null},
  {t:"Welcher Glaube an dich selbst würde alles andere einfacher machen, wenn du ihn heute ändern würdest?", a:null},
  {t:"Wie viel von dem, was Sie heute als Einschränkung empfinden, ist eine echte Einschränkung und wie viel ist eine Geschichte, die Sie nie in Frage gestellt haben?", a:null},
  {t:"Wozu sagen Sie „Ja“, weil Sie nicht den Mut haben, „Nein“ zu sagen?", a:null},
  {t:"Wenn Ihr Leben ein Unternehmen wäre, würden Sie es finanzieren? Oder würden Sie die Strategie ändern?", a:null},
  {t:"Was würden Sie heute tun, wenn Sie wüssten, dass die Version von Ihnen in einem Jahr Ihnen dafür danken würde, dass Sie es getan haben?", a:null},
  {t:"Wie anders würde Ihr Leben aussehen, wenn Sie Ihre Träume genauso ernst nehmen würden wie Ihre Verpflichtungen?", a:null},
  {t:"Gibt es etwas, von dem Sie wissen, dass Sie es ändern sollten, und Sie wissen seit mehr als einem Jahr, dass Sie es ändern sollten?", a:null},
  {t:"Welchen Teil Ihrer Identität schützen Sie, der Ihnen eigentlich nicht mehr dient?", a:null},
  {t:"Wie viel von dem, was Sie als „realistisch sein“ bezeichnen, ist eigentlich die Angst vor Enttäuschung durch einen respektableren Namen?", a:null},
  {t:"Was müssten Sie über sich selbst glauben, damit das, was Sie wollen, möglich und nicht nur wünschenswert erscheint?", a:null},
  {t:"Wann haben Sie das letzte Mal etwas getan, das Ihnen wirklich Angst gemacht hat und das gut geklappt hat?", a:null},
  {t:"Worauf warten Sie noch, um sich äußerlich zu verändern, damit Sie anfangen können, das zu tun, von dem Sie wissen, dass Sie es innerlich tun müssen?", a:null},
  {t:"Wenn der Job, den Sie heute machen, der letzte Job wäre, den Sie machen könnten, würden Sie dann die Art und Weise ändern, wie Sie ihn machen?", a:null},
  {t:"Fragst du jemanden, der dir niemals die Erlaubnis geben wird, so zu sein, wie du sein möchtest?", a:null},
  {t:"Der Zweck wurde nicht gefunden. Es ist an der Schnittstelle zwischen dem, was Ihnen am Herzen liegt, und dem, was die Welt braucht, aufgebaut.", a:null},
  {t:"Wayne Dyer hat es so auf den Punkt gebracht: Du stirbst nicht, wenn dein Herz stehen bleibt. Du stirbst an dem Tag, an dem du aufhörst zu glauben, dass deine Anwesenheit hier einen Sinn hat.", a:"W. Dyer"},
  {t:"Ohne Orientierung zu leben ist keine Freiheit. Es ist die teuerste Lebensweise, weil man Energie verbraucht, ohne Bewegung zu erzeugen.", a:null},
  {t:"Es gibt einen Unterschied zwischen dem, was man tut, um zu überleben, und dem, was man tut, um das Gefühl zu haben, dass es sich gelohnt hat, hier gewesen zu sein.", a:null},
  {t:"Nicht jeder wird mit dem Wissen geboren, wozu er da ist. Aber jeder hat die Fähigkeit, dieses Ziel mit den Werkzeugen zu erreichen, die ihm das Leben bereits gegeben hat.", a:null},
  {t:"Gleichgültigkeit ist gefährlicher als Scheitern. Zumindest bedeutet ein Scheitern, dass Sie etwas versucht haben, das Ihnen am Herzen liegt.", a:null},
  {t:"Auf der Grundlage der Zustimmung anderer Menschen zu leben bedeutet, sich dafür zu entscheiden, andere die eigene Geschichte schreiben zu lassen.", a:null},
  {t:"Es gibt Menschen, die am Ende ihres Lebens Erfolge vorweisen, die sie nicht hatten. Sie erreichten, was andere von ihnen erwarteten, nicht das, was sie brauchten, um sich ganz zu fühlen.", a:null},
  {t:"Paulo Coelho hat es auf eine Weise gesagt, die nur wenige vergessen: Wenn man etwas wirklich will, verschwor sich das gesamte Universum, um es zu erreichen. Aber „wirklich wollen“ bedeutet, bereit zu sein, die Kosten zu tragen.", a:"P. Coelho"},
  {t:"Es gibt nichts Ehrenhafteres, als zu wissen, was man will, es transparent zu machen und in diese Richtung zu arbeiten, ohne sich zu entschuldigen.", a:null},
  {t:"Vermächtnis ist nicht das, was man hinterlässt, wenn man geht. Es ist das, was Sie an den Menschen verändert haben, die das Privileg hatten, Sie zu kennen.", a:null},
  {t:"Das Leben, das Sie sich wünschen, ist möglich. Die Frage ist, ob Sie bereit sind, die Person zu sein, die das Leben erfordert.", a:null},
  {t:"Das, was man liebt, mit Exzellenz zu tun, ist gleichzeitig die großzügigste Tat, die man für die Welt tun kann.", a:null},
  {t:"Die Leere, die du fühlst, wenn nichts einen Sinn ergibt, ist kein Zeichen dafür, dass du gebrochen bist. Es ist der Druck, der der Klarheit vorausgeht.", a:null},
  {t:"Sie sind nicht hier, um sich anzupassen. Sie sind hier, um etwas beizutragen, was niemand sonst auf die gleiche Weise beitragen kann.", a:null},
  {t:"Es gibt Zeiten, in denen das Leben einen fragt, wer man wirklich ist. Wie Sie in diesen Momenten reagieren, bestimmt alles andere.", a:null},
  {t:"Marcus Aurelius schrieb jeden Morgen, um sich daran zu erinnern, wer er sein wollte. An dem Tag, an dem wir diese Erinnerung nicht mehr brauchen, sind wir perfekt. Dieser Tag kommt nicht.", a:"M. Aurelio"},
  {t:"Es gibt nur einen Unterschied, den Epictetus als grundlegend ansah: Was hängt von Ihnen ab und was nicht. Sie zu verwirren ist die Quelle fast allen unnötigen Leidens.", a:"Epicteto"},
  {t:"Seneca hat es mit einer Klarheit geschrieben, die unangenehm ist: Es ist nicht so, dass wir wenig Zeit haben. Es ist nur so, dass wir viel verschwenden.", a:"Séneca"},
  {t:"Stoizismus lehrt nicht, nicht zu fühlen. Es lehrt Sie, Ihr Handeln nicht von Ihren Gefühlen bestimmen zu lassen.", a:null},
  {t:"Marcus Aurelius war Kaiser der bekannten Welt und er erinnerte sich jeden Morgen daran: Tu, was die Natur verlangt. Heute. Keine Ausreden.", a:"M. Aurelio"},
  {t:"Widrigkeiten bilden keinen Charakter. Es offenbart es. Und wenn Ihnen das, was es preisgibt, nicht gefällt, ist das die wertvollste Information, die Sie erhalten können.", a:null},
  {t:"Der Schmerz, den Sie heute vermeiden, findet Sie morgen normalerweise mit angehäuftem Interesse wieder.", a:null},
  {t:"Seneca fragte: Warum Lebensjahre ansammeln, wenn man in diesen Jahren kein Leben ansammelt?", a:"Séneca"},
  {t:"Fordern Sie nicht, dass Ereignisse so ablaufen, wie Sie es sich wünschen. Bereiten Sie sich darauf vor, so zu sein, wie Sie sein müssen, egal welche Ereignisse passieren.", a:null},
  {t:"Der Weise, sagte Epictetus, leidet nicht unter dem, was ihm fehlt. Arbeiten Sie mit dem, was Sie haben, und verwechseln Sie nicht den Unterschied.", a:"Epicteto"},
  {t:"Es gibt eine Freiheit, die Ihnen niemand nehmen kann: die Freiheit zu entscheiden, wie Sie auf das reagieren, was Sie durchleben müssen.", a:null},
  {t:"Marcus Aurelius wusste es: Du bist, was du immer wieder tust. Nicht das, was Sie vorhaben, nicht das, als was Sie sich selbst beschreiben. Was Sie tun", a:"M. Aurelio"},
  {t:"Eine Beschwerde ohne Maßnahmen bedeutet, dass Energie darauf verwendet wird, das Problem zu bestätigen. Die gleiche Energie, die auf die Lösung gerichtet ist, verändert sie.", a:null},
  {t:"Seneca betonte: Denken Sie oft an den Tod, nicht um sich selbst traurig zu machen, sondern um jede Stunde, die ihm vorausgeht, besser zu nutzen.", a:"Séneca"},
  {t:"Der Charakter wird nicht an angenehmen Tagen aufgebaut. Es wurde in einer Zeit gebaut, in der Bequemlichkeit eine einfache Option war und man sich nicht dafür entschieden hat.", a:null},
  {t:"Um gut zu sein, müssen die Dinge nicht einfach sein. Sie müssen nur wissen, dass Sie mit den schwierigen Dingen umgehen können.", a:null},
  {t:"Der Stoiker behauptet nicht, dass es keinen Schmerz gäbe. Stellen Sie sich vor, dass der Schmerz nicht der letzte Entscheidungsträger Ihrer Entscheidungen ist.", a:null},
  {t:"Es liegt mehr Macht darin, Ihre Reaktion zu wählen, als die Kontrolle darüber zu haben, was mit Ihnen geschieht.", a:null},
  {t:"Was andere über Sie denken, ist Ihre Aufgabe. Was du von dir denkst, gehört dir.", a:null},
  {t:"Chancen verschwinden nicht. Sie bewegen sich auf Menschen zu, die bereit sind, sie zu sehen.", a:null},
  {t:"Der Moment, auf den Sie gewartet haben, ist schon lange der Moment, in dem Sie sich befinden.", a:null},
  {t:"The window to do something important doesn't close when you decide you're not ready. Es schließt sich, wenn Sie nicht mehr am Leben sind.", a:null},
  {t:"Es gibt Menschen, die die gleiche Realität wie Sie betrachten und eine Chance sehen, wo Sie ein Hindernis sehen. Sie haben keine weiteren Informationen. Sie haben eine andere Perspektive.", a:null},
  {t:"Nicht jede Gelegenheit bringt ein Schild mit der Aufschrift „Chance“ mit sich. Die meisten werden als harte Arbeit, ein ungelöstes Problem oder ein unangenehmes Gespräch getarnt.", a:null},
  {t:"Die Gegenwart ist der einzige Ort, an dem man handeln kann. Die Vergangenheit ist Studium. Die Zukunft ist Richtung. Aber die Aktion passiert erst jetzt.", a:null},
  {t:"Jeder Mensch, der zu spät an seinem Ziel ankam, hatte vorher einen Moment, in dem er noch den Kurs ändern konnte. Dieser Moment ist fast immer heute.", a:null},
  {t:"Was die Menschen „schlechte Zeiten“ nennen, ist für diejenigen, die die Augen offen haben, normalerweise die Zeit der größten Fruchtbarkeit.", a:null},
  {t:"Seien Sie nicht so damit beschäftigt, über den Verlust zu trauern, dass Sie verpassen, was auf Sie zukommt.", a:null},
  {t:"Es gibt Menschen, die ihr Leben in einem Moment verändern, der von außen gewöhnlich erscheint. Die Magie lag nicht im Augenblick. Ich war in der Entscheidung.", a:null},
  {t:"Der Moment der Klarheit, den Sie suchen, findet normalerweise auf der anderen Seite des Geschehens statt, nicht davor.", a:null},
  {t:"Die Chancen, die Sie in der Vergangenheit genutzt haben, schienen riskant, bevor Sie sie genutzt haben. Die, die du auch gemieden hast.", a:null},
  {t:"Eckhart Tolle hat es sein ganzes Leben lang auf unterschiedliche Weise gelehrt: Die Kraft liegt im Jetzt, weil das Jetzt das Einzige ist, was wirklich existiert.", a:"E. Tolle"},
  {t:"Die Person, die Sie heute sind, hat Entscheidungen getroffen, die die Person, die Sie waren, nicht für möglich gehalten hätte. Der Mensch von morgen braucht den Menschen von heute, um dasselbe zu tun.", a:null},
  {t:"Sie können nichts Dauerhaftes auf der Grundlage aufbauen, dass Sie das, was Sie aufbauen, nicht verdienen.", a:null},
  {t:"Sich selbst gut zu behandeln ist kein Privileg, das man sich verdient, wenn man alles erreicht hat. Es ist der Ausgangspunkt, um etwas erreichen zu können.", a:null},
  {t:"Das Ausmaß der Behandlung, die Sie von anderen annehmen, spiegelt fast immer die Behandlung wider, die Sie sich selbst privat zukommen lassen.", a:null},
  {t:"Die Beziehung, die Sie zu sich selbst haben, ist die Vorlage, auf der Sie alles andere aufbauen. Deshalb ist die innere Arbeit nicht von der äußeren Arbeit getrennt.", a:null},
  {t:"Den Rest musst du nicht verdienen. Den Frieden muss man sich nicht verdienen. Dabei handelt es sich um Grundbedingungen, nicht um Belohnungen.", a:null},
  {t:"Sie können gleichzeitig anspruchsvoll und freundlich sein. Sie sind keine Gegensätze. Sie sind die produktivste Kombination, die es gibt.", a:null},
  {t:"Lähmender Perfektionismus ist kein Maßstab für Exzellenz. Es ist die Angst vor einem Urteil, das als Strenge getarnt ist.", a:null},
  {t:"Anerkennen, was man erreicht hat, ist keine Konformität. Es ist der Treibstoff, der die Bemühungen, weiterhin nachhaltig zu wachsen, ermöglicht.", a:null},
  {t:"Niemand kann Ihnen die Bestätigung geben, die Sie brauchen, weil Sie sie von der einzigen Quelle benötigen, die sie Ihnen nicht geben kann: sich selbst.", a:null},
  {t:"Die Arbeit, die Sie lieben, und die Arbeit, die Sie gut machen, sind am Anfang nicht immer gleich. Aber Exzellenz in jedem Job öffnet Türen, die leidenschaftliche Mittelmäßigkeit nicht bieten kann.", a:null},
  {t:"Ehrliche Arbeit hat eine Würde, die kein Scheck kaufen und keine Härte nehmen kann.", a:null},
  {t:"Der Wert, den Sie für andere schaffen, ist die einzige Währung, die das Universum niemals abwertet.", a:null},
  {t:"Man kann sich nicht immer aussuchen, woran man arbeitet. Sie können jederzeit wählen, wie Sie arbeiten. Und diese Wahl verändert jeden Job.", a:null},
  {t:"Die Arbeit, die niemand sieht, bringt die Ergebnisse hervor, die jeder bewundert. Das war immer so.", a:null},
  {t:"Es gibt Menschen, die arbeiten, um ihren Lebensunterhalt zu verdienen, und Menschen, die arbeiten, um etwas aufzubauen. Der Unterschied liegt nicht im Job. Es liegt in der Absicht.", a:null},
  {t:"Exzellenz ist keine Perfektion. Es ist die Verpflichtung, das, was man bereits gut kann, immer besser zu machen.", a:null},
  {t:"Jede Fähigkeit, die Sie mit Mühe entwickelt haben, gehört für immer Ihnen. Niemand kann es dir wegnehmen. Das ist die wahrste Form von Sicherheit, die es gibt.", a:null},
  {t:"Es ist keine unbedeutende Arbeit, wenn man sie mit dem Bewusstsein erledigt, dass man damit den Tag eines Menschen verändert.", a:null},
  {t:"Die fünf Menschen, mit denen Sie die meiste Zeit verbringen, beeinflussen nicht nur Ihre Stimmung. Sie beeinflussen Ihr Dach.", a:null},
  {t:"Es gibt Menschen, die dich erweitern, und Menschen, die dich zusammenziehen. Im Laufe der Zeit ist die Wahl, mit wem Sie Zeit verbringen, eine der wichtigsten Entscheidungen Ihres Lebens.", a:null},
  {t:"Großzügiges Geben ist kein Risiko. Es ist die Investition mit der unvorhersehbarsten und zugleich realsten Rendite.", a:null},
  {t:"Niemand kommt alleine irgendwohin, wo es wichtig ist. Hinter jeder Leistung steht jemand, der vor dem Betroffenen geglaubt hat.", a:null},
  {t:"Die wirkliche Konkurrenz besteht nicht mit denen, die das Gleiche tun wie Sie. Der wirkliche Wettbewerb besteht in der Version von Ihnen, die Sie werden können.", a:null},
  {t:"Jemandem beim Wachsen zu helfen, nimmt dir nichts. Im Gegenteil, es versetzt Sie in die Art von Welt, in der Sie leben möchten.", a:null},
  {t:"Die Menschen, die Ihre Standards erhöhen, verdienen Ihre Zeit und Energie. Diejenigen, die es herabsetzen, verdienen Ihr Mitgefühl, aber nicht Ihre Absichten.", a:null},
  {t:"Der Einfluss, den Sie auf das Leben anderer haben, ist selten das, was Sie erwartet haben. Manchmal verändert ein einziges Gespräch den Werdegang einer Person.", a:null},
  {t:"Die Veränderung, die Sie anstreben, erfordert immer, dass die Person, die Sie nicht mehr sein müssen, bereit ist, loszulassen.", a:null},
  {t:"Transformieren bedeutet nicht, das zu ersetzen, was du bist. Es bedeutet, das zu integrieren, was Sie sein müssen, ohne das zu zerstören, was Sie bereits aufgebaut haben.", a:null},
  {t:"In jeder echten Transformation gibt es einen Moment, in dem man scheinbar einen Rückschritt macht. Dieser Moment ist nicht das Ende des Prozesses. Es ist der tiefste Teil von ihm.", a:null},
  {t:"Die Veränderung, die Sie heute privat vornehmen, wird in einem Jahr in der Öffentlichkeit auffallen.", a:null},
  {t:"Reales Wachstum ist fast nie ein Vorbote dafür, dass es kommt. Es erscheint als Unbehagen, Reibung und erst später als Klarheit.", a:null},
  {t:"Es ist keine Inkonsistenz, Ihre Meinung zu ändern, wenn Sie über neue Informationen verfügen. Es ist Intelligenz.", a:null},
  {t:"Die Person, die Sie waren, hat mit dem, was Sie hatten, getan, was Sie konnten. Die Person, die du bist, kann mehr tun. Das ist alles, was das Erwachsenwerden mit sich bringt.", a:null},
  {t:"Jede Version von dir, die du nicht mehr bist, war notwendig, um zu der zu gelangen, die du jetzt bist. Verurteile sie nicht. Es war der Weg.", a:null},
  {t:"Die Angst vor Veränderung und der Wunsch nach Veränderung können nebeneinander bestehen. Sie müssen nicht warten, bis die Angst verschwindet, um zu beginnen.", a:null},
  {t:"Es gibt etwas, das man nur von der anderen Seite der Veränderung aus erkennen kann. Deshalb kann Ihnen niemand, der es noch nicht gemacht hat, die Karte geben.", a:null},
  {t:"Die Identität, die Sie am schwersten loslassen können, ist normalerweise diejenige, die Sie am meisten einschränkt.", a:null},
  {t:"Der beste Nutzen aus der Vergangenheit besteht nicht darin, sie zu bewohnen. Man lernt genug daraus, um es nicht zu wiederholen.", a:null},
  {t:"Es gibt keine Dringlichkeit, die ein Leben rechtfertigt, das nur einmal in Eile geschieht.", a:null},
  {t:"In zwanzig Jahren werden die Dinge, die Sie bereuen, nicht in erster Linie die Dinge sein, die Sie getan haben. Es werden diejenigen sein, die du nicht gewagt hast.", a:null},
  {t:"Das Vermächtnis entsteht nicht am Ende des Lebens. Es basiert auf der Summe, wie Sie jede Person behandelt haben, die Ihren Weg kreuzte.", a:null},
  {t:"Es gibt Menschen, die sterben mit 30 und werden mit 80 begraben. Der Unterschied zwischen Leben und Existieren besteht darin, ob man aktiv wählt oder einfach nur wartet.", a:null},
  {t:"Jedes Jahr, das ziellos vergeht, ist ein Jahr, das man nicht zurückbekommen kann. Das soll dir keine Angst machen. Es liegt an Ihnen, das zu schätzen, was Sie noch haben.", a:null},
  {t:"Die Zeit, die Sie investieren, um sich selbst kennenzulernen, ist niemals verschwendete Zeit. Es ist die Karte, ohne die jedes Ziel zufällig erreicht wird.", a:null},
  {t:"Die Samen entschuldigen sich nicht dafür, dass es lange dauert, bis sie keimen. Der von außen nicht sichtbare Prozess macht das später Gesehene erst möglich.", a:null},
  {t:"Es gibt eine Art Vertrauen, das nicht davon abhängt, dass man sich über das Ergebnis sicher sein kann. Es kommt darauf an, dass Sie sich bei der Suche darüber im Klaren sind, wer Sie sind.", a:null},
  {t:"Nicht alles, was wie ein Umweg erscheint, ist ein Fehler. Manchmal ist der längste Weg der, der Sie bereit macht, anzukommen.", a:null},
  {t:"Dem Prozess zu vertrauen bedeutet nicht, nicht zu handeln. Es bedeutet, zu handeln, ohne verzweifelt daran festzuhalten, dass das Ergebnis genau so ist, wie Sie es sich vorgestellt haben.", a:null},
  {t:"Es gibt Zeiten, in denen das Einzige, was Sie tun können, ist, weiterzumachen und zu hoffen, dass sich später ein Sinn ergibt. Dieses aktive Warten ist auch ein Akt des Mutes.", a:null},
  {t:"Ungeduld beschleunigt selten Ergebnisse. Es macht sie fast immer komplizierter.", a:null},
  {t:"Wenn alles still zu sein scheint, denken Sie daran, dass Bambus jahrelang unter der Erde wächst, bevor ihn jemand sehen kann.", a:null},
  {t:"Es gibt Phasen im Leben, die dem Winter ähneln. Sie sind nicht das Ende des Zyklus. Sie sind die Vorbereitung auf das, was als nächstes kommt.", a:null},
  {t:"Das Vertrauen in den Prozess ist schwerer aufrechtzuerhalten als das Vertrauen in das Ergebnis. Und es ist auch ehrlicher.", a:null},
  {t:"Sie müssen nicht alles sehen, um den nächsten Schritt zu tun. Sie müssen nur genug sehen, um diesen Schritt zu ermöglichen.", a:null},
  {t:"Hoffnung ist nicht die Gewissheit, dass alles gut wird. Es ist die Überzeugung, dass Sie das haben, was Sie brauchen, um auf alles zu reagieren, was herauskommt.", a:null},
  {t:"Die Tatsache, dass Sie nach etwas Besserem suchen, ist bereits ein Zeichen dafür, dass Sie irgendwo in Ihrem Inneren wissen, dass es möglich ist.", a:null},
  {t:"Nicht alle Menschen, die dort angekommen sind, wo Sie anfangen möchten, haben mehr Vorteile als Sie. Viele begannen mit weniger.", a:null},
  {t:"Solange Sie weiter wählen, ist das Spiel noch nicht vorbei.", a:null},
  {t:"Jede Verbesserungsgeschichte, die Sie bewegt, bewegt Sie, weil Sie darin etwas erkennen, das auch für Sie möglich ist.", a:null},
  {t:"Die berechtigte Hoffnung ist nicht die, die darauf wartet, dass die Dinge von selbst besser werden. Sie ist diejenige, die so tut, als ob es besser werden könnte, und entsprechend handelt.", a:null},
  {t:"Es gibt Menschen, die ihr Leben mit 50 verändert haben. Es gibt Menschen, die es mit 60 getan haben. Der einzige Moment, der verloren geht, ist der, den man ohne Entscheidung verstreichen lässt.", a:null},
  {t:"Berechtigter Optimismus leugnet die Schwierigkeit nicht. Er akzeptiert es und beschließt, trotzdem zu handeln.", a:null},
  {t:"Die Version Ihres Lebens, die Sie noch nicht gelebt haben, ist nicht nur ein Traum. Es ist eine echte Möglichkeit, die darauf wartet, dass Sie sich in ihre Richtung bewegen.", a:null},
  {t:"Für die Anerkennung anderer zu leben ist kein Leben. Es bedeutet, in einem Stück zu spielen, das andere geschrieben haben, und darauf zu warten, dass der Applaus die Lücke füllt.", a:null},
  {t:"Authentizität ist für die Menschen um Sie herum nicht immer angenehm. Aber es ist das einzige Fundament, auf dem man etwas Dauerhaftes aufbauen kann.", a:null},
  {t:"Es entsteht eine besondere Müdigkeit, wenn man vorgibt, etwas zu sein, was man nicht ist. Es ist teurer als jede andere Anstrengung.", a:null},
  {t:"Nicht jeder wird verstehen, was Sie bauen möchten. Das ist kein Zeichen dafür, dass es falsch ist. Manchmal ist es ein Zeichen dafür, dass es dir gehört.", a:null},
  {t:"Die Person, die du bist, wenn niemand hinschaut, ist die wahre Person. Alles andere ist Präsentation.", a:null},
  {t:"Das Leben, das Sie um das herum aufbauen, was Sie wollen sollen, befriedigt Sie selten, selbst wenn Sie es bekommen.", a:null},
  {t:"Es hat etwas Befreiendes, wenn man aufhört, jeden dazu zu bringen, einen zu mögen, und stattdessen ehrlich darüber ist, wer man ist und wohin man geht.", a:null},
  {t:"Die Stimme, die dir sagt, dass du nicht du selbst sein und gleichzeitig erfolgreich sein kannst, ist falsch. Und es gibt Tausende von Menschen, die es versuchen.", a:null},
  {t:"Für das, was man wirklich ist, anerkannt zu werden, ist unendlich mehr wert, als für das, was man vorgibt, bewundert zu werden.", a:null},
  {t:"Wie anders würde Ihr Leben aussehen, wenn Sie glauben würden, dass Sie genau das verdienen, was Sie wollen?", a:null},
  {t:"Der Unterschied zwischen denen, die viel und denen, die wenig haben, besteht nicht immer. Manchmal kommt es darauf an, wie tief jeder Mensch davon überzeugt ist, dass er verdient, was er sucht.", a:null},
  {t:"Niemand wird dir die Erlaubnis geben, so zu sein, wie du bist. Diese Autorisierung existiert nur in Ihnen.", a:null},
  {t:"Angst vor dem Scheitern ist ein Schutzmechanismus. Aber es schützt vor etwas, das möglicherweise nie eintritt, und bewahrt Sie vor etwas, das definitiv passieren könnte.", a:null},
  {t:"Jedes Mal, wenn Sie sich dafür entscheiden, aus echter Leidenschaft statt aus Angst zu handeln, ist das Ergebnis ein anderes, auch wenn die Handlung gleich zu sein scheint.", a:null},
  {t:"Die Klarheit, die Sie suchen, stellt sich selten ein, bevor Sie beginnen. Es ist fast immer die Belohnung dafür, dass man angefangen hat.", a:null},
  {t:"Es gibt keine Karte für den genauen Ort, wohin Sie wollen. Es gibt einen Kompass. Und der Kompass ist das, was Ihnen wirklich wichtig ist.", a:null},
  {t:"Was Sie am meisten über sich preisgeben möchten, ist normalerweise das, was andere am meisten berührt, wenn Sie es teilen.", a:null},
  {t:"Es gibt eine Zone zwischen Ihrem Standort und Ihrem Ziel, die Arbeit, Geduld und Glaube genannt wird. Es gibt keine zertifizierte Verknüpfung.", a:null},
  {t:"An dem Tag, an dem Sie aufhören, Ihre Fortschritte mit denen anderer zu vergleichen, und sie mit Ihren von gestern vergleichen, wird sich Ihr Leben beschleunigen.", a:null},
  {t:"Nicht alles, was schlecht beginnt, endet schlecht. Nicht alles, was gut beginnt, endet auch gut. Was zählt, ist, was Sie in der Mitte tun.", a:null},
  {t:"Es gibt einen Unterschied zwischen Aufgeben und dem Wissen, wann man die Strategie ändern muss. Der erste schließt Türen. Der zweite öffnet sie.", a:null},
  {t:"Was Sie am meisten zu lernen kostet, ist das, was Ihnen am meisten gehört und was Sie am großzügigsten geben können.", a:null},
  {t:"Es liegt eine Würde darin, es weiter zu versuchen, die Ihnen kein Ergebnis nehmen kann.", a:null},
  {t:"Jedes Hindernis, dem Sie heute gegenüberstehen, hat genau die Größe, die Sie benötigen, um auf die nächste Stufe zu gelangen.", a:null},
  {t:"Wahre Stärke besteht nicht darin, keine Angst zu haben. Es bedeutet, immer wieder Angst zu haben und zu handeln, bis es zur Gewohnheit wird.", a:null},
  {t:"Das Projekt, das nicht begonnen wurde, die Idee, die nicht umgesetzt wurde, das Gespräch, das nicht geführt wurde: Das sind die teuersten Schulden, die es gibt.", a:null},
  {t:"Es gibt etwas, das nur Sie auf die Art und Weise tun können, wie Sie es tun. Das zu finden und umzusetzen ist die Mission.", a:null},
  {t:"La fe más valiosa no es la que aparece cuando todo va bien. Es la que se sostiene cuando nada parece funcionar.", a:null},
  {t:"Sie müssen den Weg nicht vollständig verstehen, um den nächsten Schritt zu tun. Sie müssen nur daran glauben, dass der nächste Schritt irgendwohin führt.", a:null},
  {t:"Jedes Mal, wenn Sie Dankbarkeit der Beschwerde vorziehen, betätigen Sie einen Hebel, der mehr Dinge bewegt, als Sie sehen können.", a:null},
  {t:"Das Universum reagiert nicht auf das, was Sie sagen. Reagieren Sie tief genug auf das, was Sie glauben, um Ihr Verhalten zu ändern.", a:null},
  {t:"Die einflussreichsten Menschen, die Sie kennen, haben eines gemeinsam: Sie haben entschieden, dass ihre Geschichte nicht dort endet, wo andere dachten, sie würde enden.", a:null},
  {t:"Was Ihnen heute unmöglich erscheint, ist das, was jemand irgendwo auf der Welt endlich mit weniger als Ihnen erreicht.", a:null},
  {t:"Mit Absicht zu leben ist keine Garantie dafür, dass alles gut wird. Es stellt sicher, dass sich der Versuch gelohnt hat, wenn etwas schief geht.", a:null},
  {t:"Das Leben, das Sie sich wünschen, wartet nicht darauf, dass Sie perfekt sind. Es wartet darauf, dass Sie beginnen.", a:null},
  {t:"Verletzlichkeit ist keine Schwäche. Es ist der Zustand, von dem aus die wahrhaftigsten und mutigsten Dinge getan werden.", a:null},
  {t:"Es gibt eine Form von Mut, die niemand begrüßt: die, weiterhin an das Private zu glauben, wenn alles Äußere sagt, dass man falsch liegt.", a:null},
  {t:"Zuzugeben, dass man es nicht weiß, ist der erste Schritt zum Wissen. So zu tun, als wüsste man es, ist der erste Schritt zur Stagnation.", a:null},
  {t:"Mut ist kein Persönlichkeitsmerkmal. Es ist eine Entscheidung, die zu einem bestimmten Zeitpunkt getroffen wird und mit der Übung zur Gewohnheit wird.", a:null},
  {t:"Es gibt einen Unterschied zwischen dem Risiko aus Angst und dem Risiko aus Überzeugung. Die Ergebnisse sind unterschiedlich, auch wenn die Aktion gleich zu sein scheint.", a:null},
  {t:"Um Hilfe zu bitten ist kein Zeichen dafür, dass Sie es nicht können. Es ist ein Zeichen dafür, dass Sie wissen, wann das Problem größer ist als Ihr Ego.", a:null},
  {t:"Es erfordert einen besonderen Mut, etwas Neues zu beginnen, in einem Alter, in dem jeder erwartet, dass man bereits alles herausgefunden hat.", a:null},
  {t:"Die Wahrheit zu sagen, wenn es unangenehm ist, ist ehrenhafter, als zu lügen, wenn es bequem ist. Und auf lange Sicht profitabler.", a:null},
  {t:"Wer niemals scheitert, hat nie etwas Sinnvolles versucht. Die Narben sind der Preis dafür, dass man im Feld gewesen ist.", a:null},
  {t:"Jeder Mensch hat eine einzigartige Art, die Welt zu sehen. Es ehrlich auszudrücken, ist der wichtigste kreative Akt, den Sie tun können.", a:null},
  {t:"Kreativität ist keine Gabe, die manche haben und andere nicht. Es handelt sich um eine Fähigkeit, die verkümmert, wenn sie nicht genutzt wird, und die sich bei Ausübung entfaltet.", a:null},
  {t:"Die Angst, etwas Unvollkommenes zu machen, tötet mehr Projekte als ein Mangel an Talent.", a:null},
  {t:"Etwas zu erschaffen, auch wenn es noch so klein ist, ist ein Ausdruck dafür, dass man davon überzeugt ist, etwas zur Welt beitragen zu können, was vorher nicht existierte.", a:null},
  {t:"Es gibt eine Befriedigung, die nur das eigene Werk hervorbringt, das Ihre Handschrift trägt, auch wenn sie noch niemand erkennt.", a:null},
  {t:"Ideen, die nicht umgesetzt werden, existieren nicht. Sie sind lediglich Möglichkeiten, die in einem Raum schweben, in dem die Realität sie nicht erreichen kann.", a:null},
  {t:"Kreative Arbeit gilt als ständiger Begleiter. Der Unterschied zwischen denen, die glauben, und denen, die nicht glauben, besteht darin, dass man sich dafür entschieden hat, dasselbe zu tun.", a:null},
  {t:"Es gibt etwas, das erst dann erscheint, wenn man damit anfängt. Es erscheint nie, während Sie noch planen.", a:null},
  {t:"Ihre einzigartige Sicht auf die Welt, die manchmal seltsam oder fehl am Platz erscheint, ist genau das, was jemand irgendwo hören muss.", a:null},
  {t:"Der Fehler, den Sie erkennen und verstehen, hat Sie etwas Wertvolles gekostet, Ihnen aber etwas noch Wertvolleres hinterlassen.", a:null},
  {t:"Aus einem Fehler nicht zu lernen bedeutet, ihn zweimal zu machen. Daraus zu lernen bedeutet, Kosten in Investitionen umzuwandeln.", a:null},
  {t:"Es gibt Menschen, die aus ihren Erfahrungen lernen, und Menschen, die aus den Erfahrungen anderer lernen. Letztere zahlen dabei weniger.", a:null},
  {t:"Kritik, die wehtut, hat manchmal mehr Wahrheit als Lob, das tröstet.", a:null},
  {t:"Einen Fehler in Richtung des Ziels zu machen, ist etwas völlig anderes, als sich aus Angst vor einem Fehler nicht zu bewegen.", a:null},
  {t:"Jede Fähigkeit, die Ihnen heute selbstverständlich erscheint, war einst etwas, von dem Sie nicht wussten, wie man es macht, und das Sie beschlossen haben, zu lernen.", a:null},
  {t:"Wissen ohne Anwendung ist Information. Auch wenn Wissen unvollkommen angewendet wird, ist es Weisheit im Entstehen.", a:null},
  {t:"Niemand meistert jemals etwas, ohne die peinliche Phase zu durchlaufen, in der man es falsch macht und gleichzeitig lernt, es richtig zu machen.", a:null},
  {t:"Intellektuelle Bescheidenheit, die Bereitschaft, Ihre Meinung zu ändern, wenn Sie über bessere Daten verfügen, ist eine der seltensten und wertvollsten Fähigkeiten.", a:null},
  {t:"Es gibt einen Unterschied zwischen der Verarbeitung eines Fehlers und dem Grübeln darüber. Einer bringt dich voran. Der andere hält Sie am selben Punkt.", a:null},
  {t:"Was für Sie am schwierigsten zu verstehen war, ist, was Sie tiefergehender lehren können.", a:null},
  {t:"Der Baum, der dem stärksten Wind standhält, hat die tiefsten Wurzeln. Es ist kein Zufall.", a:null},
  {t:"Der Diamant weiß nicht, dass er wertvoll ist. Ihr Wert hängt nicht von Ihrem Selbstbewusstsein ab. Aber der Mensch kann sich dafür entscheiden, zu wissen, wie viel er wert ist.", a:null},
  {t:"Der Fluss zweifelt nicht am Weg, weil er einen Stein findet. Er umgibt es, poliert es und fährt fort.", a:null},
  {t:"Es gibt Samen, die unter scheinbar unmöglichen Bedingungen keimen. Auch die Wüste blüht nach dem richtigen Regen.", a:null},
  {t:"Der Mond verschwindet nicht, wenn man ihn nicht sehen kann. Dunkelheit löscht nicht das Bestehende aus.", a:null},
  {t:"Für den Vogelflug ist kein Verständnis der Aerodynamik erforderlich. Es erfordert, dass sie dem vertrauen, was sie von Natur aus zu tun wissen.", a:null},
  {t:"Ein einziger Funke kann unter den richtigen Bedingungen die gesamte Landschaft verändern. Unterschätzen Sie nicht den kleinen Moment, den Sie erleben.", a:null},
  {t:"Der Ozean liegt weder an der Oberfläche noch am Grund. Aber tief im Inneren ist die Ruhe tiefer. Finden Sie Ihren Hintergrund.", a:null},
  {t:"Geld ist ein Verstärker. Verstärke, was du bereits bist. Deshalb ist es kein Idealismus, den Charakter vor dem Reichtum zu stärken, sondern Strategie.", a:null},
  {t:"Es gibt Menschen, die hart arbeiten, um Geld zu verdienen, und Menschen, die hart arbeiten, um Werte zu schaffen. Die zweite Kategorie bringt am Ende fast immer mehr Geld ein.", a:null},
  {t:"Wohlstand, der von innen heraus nicht nachhaltig ist, ist ausnahmslos vorübergehend.", a:null},
  {t:"Es gibt einen Unterschied zwischen Geld und einem gesunden Verhältnis zu Geld. Das Zweite bringt das Erste nachhaltig hervor.", a:null},
  {t:"Die Angst, Geld zu verlieren, führt zu Entscheidungen, die kostspieliger sind als Geld zu verlieren.", a:null},
  {t:"Zu wahrem Reichtum gehören Gesundheit, Beziehungen, Zeit, Frieden und Geld. Die ersten vier für die letzten zu opfern, ist auf lange Sicht ein schlechtes Geschäft.", a:null},
  {t:"Die Angewohnheit, mehr auszugeben, als man einnimmt, ist kein finanzielles Problem. Es ist eine Beziehung zur Unzufriedenheit, die tiefere Wurzeln hat.", a:null},
  {t:"Was Sie mit Ihren Händen, Ihrem Geist und Ihrem Charakter erschaffen können, ist die Grundlage jeder echten Sicherheit.", a:null},
  {t:"Echte Führung bedeutet, keine Anhänger zu haben. Es schafft die Voraussetzungen dafür, dass andere das Beste in sich selbst finden können.", a:null},
  {t:"Der Mensch, der sich konsequent selbst führt, führt schließlich etwas Größeres an, ohne danach zu streben.", a:null},
  {t:"Dienen bedeutet nicht, sich unterzuordnen. Es bedeutet, dass Sie sich dafür entscheiden, das Wohlergehen anderer zu einem Teil Ihres eigenen Ziels zu machen.", a:null},
  {t:"Der wertvollste Mentor ist nicht derjenige, der alle Antworten hat. Er ist derjenige, der weiß, welche Fragen er Ihnen stellen muss.", a:null},
  {t:"Es gibt eine Möglichkeit, die Welt zu beeinflussen, die keiner formalen Macht bedarf: mit einer solchen Übereinstimmung zwischen dem, was man sagt und dem, was man tut, zu leben, dass andere es nicht ignorieren können.", a:null},
  {t:"Was Sie tun, wenn Sie niemand zwingt, entscheidet darüber, ob Sie eines Tages etwas führen können, wenn die Verantwortung es erfordert.", a:null},
  {t:"Der nachhaltigste Einfluss, den Sie auf das Leben eines Menschen haben können, besteht darin, ihm zu helfen, sich selbst stärker zu sehen als zuvor.", a:null},
  {t:"Welchen Teil Ihres Lebens verlassen Sie weiterhin, wenn „alles geklärt ist“ und Sie wissen, dass dieser Moment nicht von allein kommt?", a:null},
  {t:"Wie oft hatten Sie in der Vergangenheit Angst vor etwas, das sich, sobald es passierte, als weniger schrecklich herausstellte, als Sie es sich vorgestellt hatten?", a:null},
  {t:"Was bewundern Sie am meisten an anderen und weigern sich anzuerkennen, dass es auch in Ihnen existiert?", a:null},
  {t:"Was würden Sie vom Leben verlangen, wenn Sie sicher wüssten, dass es es Ihnen geben könnte?", a:null},
  {t:"Gibt es etwas, das Sie nicht versucht haben, weil Sie versagt haben, sondern weil Sie Angst vor dem Scheitern hatten?", a:null},
  {t:"Wenn Sie niemanden brauchen würden, der Sie versteht, was würden Sie anders machen?", a:null},
  {t:"Wie hoch sind die tatsächlichen Kosten, wenn Sie noch fünf Jahre genau so weitermachen, wie Sie sind?", a:null},
  {t:"Wie viel von dem, was Sie als „Realismus“ bezeichnen, ist tatsächlich das angesammelte Gewicht früherer Enttäuschungen?", a:null},
  {t:"Wie anders wäre Ihre Beziehung zu sich selbst, wenn Sie sich selbst mit der gleichen Geduld gegenübertreten würden, die Sie denen entgegenbringen, die Sie am meisten lieben?", a:null},
  {t:"Gibt es etwas, an das Sie fest glauben und das Sie noch nicht leben, weil Sie Bedingungen erwarten, die niemals perfekt sein werden?", a:null},
  {t:"Was würden Sie heute tun, wenn Scheitern für Sie keine Option wäre?", a:null},
  {t:"Wann haben Sie sich das letzte Mal zu etwas verpflichtet, ohne einen Notausgang geplant zu haben?", a:null},
  {t:"Was müssen Sie loslassen, um zu bekommen, was Sie angeblich wollen?", a:null},
  {t:"Wenn Ihr Leben eine Geschichte wäre, die jemand anderes liest, wo im Handlungsbogen wären Sie jetzt?", a:null},
  {t:"Die Art und Weise, wie Sie interpretieren, was mit Ihnen geschieht, ist oft entscheidender als das, was mit Ihnen geschieht.", a:null},
  {t:"Zwei Menschen können das gleiche Ereignis erleben und der eine geht gestärkt daraus hervor, der andere zerstört. Der Unterschied liegt nicht im Ereignis.", a:null},
  {t:"Der Rahmen, von dem aus Sie ein Problem betrachten, bestimmt die Lösungen, die Sie sehen können. Der Wechsel des Rahmens ist das erste Werkzeug.", a:null},
  {t:"Es gibt Menschen, die Hindernisse sehen, wo andere unbeantwortete Fragen sehen.", a:null},
  {t:"Die häufigste Beschwerde bezieht sich in der Regel auf den Bereich, in dem das größte Wachstumspotenzial besteht.", a:null},
  {t:"Es gibt keine vollkommene Objektivität. Wir alle betrachten die Welt durch die Brille unserer Erfahrungen. Weisheit ist zu wissen, dass man eine Brille trägt.", a:null},
  {t:"Der Gedanke, der Sie am meisten einschränkt, ist selten der offensichtlichste. Es liegt in dem verborgen, was Sie für selbstverständlich halten.", a:null},
  {t:"Ein Perspektivenwechsel erfordert keine Veränderung der Fakten. Es erfordert die Bereitschaft, dass dieselbe Situation etwas anderes bedeutet.", a:null},
  {t:"Was wir „das Problem“ nennen, ist normalerweise das Symptom. Das eigentliche Problem liegt tiefer und liegt mehr bei Ihnen, als Sie es gerne hätten.", a:null},
  {t:"Es gibt einen Unterschied zwischen der Betrachtung der Realität, wie sie ist, und der Betrachtung, wie man sie verändern könnte. Beide Visionen sind notwendig. Der zweite, seltener.", a:null},
  {t:"Intelligenter Optimismus ignoriert Probleme nicht. Er sieht sie und sieht auch, was auf der anderen Seite sein könnte.", a:null},
  {t:"Wenn Sie die Frage, die Sie zu einer Situation stellen, ändern, ändert die Situation selbst ihre Bedeutung.", a:null},
  {t:"Die Person, die Sie werden möchten, wartet nicht darauf, dass Sie alles lösen, was Sie jetzt sind. Es wartet darauf, dass Sie anfangen, so zu tun, als ob es bereits möglich wäre.", a:null},
  {t:"Ihre aktuelle Identität ist das Ergebnis vergangener Entscheidungen. Was über die Zukunft entscheidet, sind die Identitäten, für die Sie sich heute entscheiden.", a:null},
  {t:"Es gibt Menschen, die hoffen, dass der Erfolg sie verändert. Wer Dauerhaftes erreicht, verändert zuerst, wer er ist.", a:null},
  {t:"Die Geschichte, die Sie sich selbst darüber erzählen, wer Sie sind, ist die einflussreichste aller Geschichten, die Sie hören.", a:null},
  {t:"Sich selbst zu sagen: „Ich bin jemand, der X macht“, ist wirkungsvoller, als sich selbst zu sagen: „Ich werde versuchen, X zu machen“. Identität geht Verhalten voraus.", a:null},
  {t:"Es gibt eine Version von Ihnen, die bereits weiß, wie Sie das Leben führen können, das Sie sich wünschen. Die Aufgabe besteht darin, die Lücke zwischen der aktuellen und dieser Version zu schließen.", a:null},
  {t:"Was Sie am tiefsten glauben, ist das, was Sie unter Druck zeigen.", a:null},
  {t:"Identität ist keine feste Tatsache. Es handelt sich um eine Konstruktionserzählung, die Sie anhand von Beweisen und Entscheidungen überprüfen können.", a:null},
  {t:"Was Sie im gegenwärtigen Moment über die Zukunft annehmen, wird von einer Intelligenz aufgezeichnet, die nicht argumentiert. Lauf einfach.", a:"N. Goddard"},
  {t:"Sie müssen den Mechanismus nicht verstehen, um ihn zu verwenden. Sie verstehen nicht, wie das Herz funktioniert und gleich schlägt. Der Geist funktioniert nach den gleichen Regeln.", a:"N. Goddard"},
  {t:"Der Zustand, den Sie in Ihrer Vorstellung für real halten, ist mächtiger als der Zustand, den Sie in der physischen Welt beobachten.", a:"N. Goddard"},
  {t:"Im Ergebnis zu leben, bevor man es hat, bedeutet nicht, sich selbst anzulügen. Es ist die Ausübung des einzigen Werkzeugs, das die Welt von außen von innen verändert.", a:"N. Goddard"},
  {t:"Jedes Mal, wenn Sie emotional auf die Welt reagieren, als ob Sie sie nicht ändern könnten, bestätigen Sie diese Welt.", a:"N. Goddard"},
  {t:"Wenn Sie sich Ihre Vorstellungen mit Gewissheit statt mit Angst vorstellen, hat die Welt, die Sie aufbauen, eine völlig andere Architektur.", a:"N. Goddard"},
  {t:"Das Bewusstsein, das das Problem beobachtet, und das Bewusstsein, das es geschaffen hat, sind dasselbe. Deshalb kann es es auflösen.", a:"N. Goddard"},
  {t:"Die Bewusstseinsebene, von der aus Sie Ihr Leben betrachten, bestimmt, wie groß der Raum des Möglichen erscheint.", a:"N. Goddard"},
  {t:"Goddard sagte: „Stellen Sie sich nicht vor, die Reise zu machen.“ Stellen Sie sich vor, Sie sind bereits am Ziel und erzählen jemandem, wie es war.", a:"N. Goddard"},
  {t:"Es gibt einen Seinszustand, in dem sich die Dinge, die man sich wünscht, natürlich und nicht erstrebenswert anfühlen. Die Aufgabe besteht darin, diesen Zustand zu finden und ihn zu bewohnen.", a:"N. Goddard"},
  {t:"Es gibt Dinge, die dauern so lange, wie sie dauern müssen. Eile beschleunigt sie nicht. Nur die Qualität des Wartens ändert sich.", a:null},
  {t:"Der Baum, der auf schlechtem Boden schnell wächst, fällt mit dem ersten Wind. Wer auf fruchtbarem Boden langsam wächst, überdauert Generationen.", a:null},
  {t:"Es gibt Zeiten, in denen es am klügsten ist, mit völliger Aufmerksamkeit und ohne Passivität abzuwarten.", a:null},
  {t:"Die Reife eines Prozesses kann nicht erzwungen werden. Ja, es kann gefüttert werden.", a:null},
  {t:"Nicht alles, was braucht, ist tot. Manchmal wächst es auf eine Weise, die man noch nicht sehen kann.", a:null},
  {t:"Das perfekte Timing fühlt sich selten perfekt an, wenn man es lebt. Es wird im Nachhinein erkannt.", a:null},
  {t:"Es gibt Phasen, die wie Stagnation aussehen, in Wirklichkeit aber eine Konsolidierung sind. Zu wissen, was was ist, erfordert Ehrlichkeit.", a:null},
  {t:"Aktive Geduld unterscheidet sich vom passiven Warten. Man baut. Der andere konsumiert.", a:null},
  {t:"Nicht jede Geschwindigkeit ist ein Fortschritt. Nicht jede Langsamkeit ist Verlust.", a:null},
  {t:"Manchmal ist es am produktivsten, nichts Unüberlegtes zu tun.", a:null},
  {t:"Ausruhen ist keine Zeitverschwendung. Es ist Teil des Prozesses, etwas Wertvolles zu produzieren.", a:null},
  {t:"Chronisches Burnout führt nicht zu qualitativ hochwertigen Ergebnissen. Es führt zu teuren Fehlern und reaktiven Entscheidungen.", a:null},
  {t:"Seelenfrieden ist nicht die Abwesenheit von Problemen. Es ist die Fähigkeit, mit Problemen umzugehen, ohne dass sie einen auflösen.", a:null},
  {t:"Wenn Sie Ihren Geist dazu auffordern, ohne Pause zu arbeiten, ist das so, als würden Sie einen Muskel dazu auffordern, Leistung zu erbringen, ohne sich zu erholen. Es funktioniert, bis es nicht mehr funktioniert.", a:null},
  {t:"Es gibt einen Unterschied zwischen produktiver Stille und Vermeidung. Eine Belastung. Der andere Download.", a:null},
  {t:"Sich um seine Energie zu kümmern ist kein Egoismus. Nur so kann man etwas Echtes geben.", a:null},
  {t:"Die Stille, die Sie um jeden Preis vermeiden, enthält normalerweise die Informationen, die Sie am meisten hören müssen.", a:null},
  {t:"Am Ende wird dich das Leben nicht fragen, wie oft du Angst hattest. Er wird Sie fragen, wie oft Sie gegen seinen Willen gehandelt haben.", a:null},
  {t:"Was Sie im Stillen, mit Geduld und ohne Garantien aufbauen, hat eine Solidität, mit der nichts übereilt Geschaffenes mithalten kann.", a:null},
  {t:"Jeden Tag, an dem Sie sich dafür entscheiden, in etwas Wichtigem besser zu sein als gestern, gewinnen Sie einen Krieg, von dem die meisten Menschen nicht einmal wissen, dass er geführt wird.", a:null},
  {t:"Ich bin nicht auf die Welt gekommen, um mich anzupassen. Ich bin gekommen, um etwas zu tun, das nur ich so tun kann, wie ich es tue.", a:null},
  {t:"Das Leben, das Sie wollen, und die Person, die Sie sein müssen, um es zu leben, sind dasselbe. Man kann das eine nicht haben, ohne das andere zu werden.", a:null},
  {t:"Heute ist ein guter Tag, um zu entscheiden, dass die kommende Geschichte besser ist als die, die passiert ist.", a:null},
  {t:"Das Revolutionärste, was Sie tun können, ist, fest daran zu glauben, dass es immer noch möglich ist, auch wenn alles dazu führt, dass Sie es nicht glauben.", a:null},
  {t:"Es gibt eine Version Ihres Lebens, in der Sie die Entscheidung getroffen haben, von der Sie immer wussten, dass Sie sie treffen mussten. Diese Version startet, wenn Sie entscheiden, dass sie startet.", a:null},
  {t:"Die Welt braucht, was Sie zu geben haben. Nicht Ihre perfekte Version. Deine ehrliche Version.", a:null},
  {t:"Earl Nightingale hat Jahre damit verbracht, nach dem Unterschied zwischen denen, die Erfolg haben, und denen, die es nicht schaffen, zu suchen. Er fand es in sechs Worten: Wir werden zu dem, was wir denken.", a:"E. Nightingale"},
  {t:"Wenn man Mais anpflanzt, bekommt man Mais. Wenn man Weizen anpflanzt, bekommt man Weizen. Der Geist funktioniert genauso: Er gibt genau das zurück, was Sie in ihn säen.", a:"E. Nightingale"},
  {t:"Das Problem für die Mehrheit besteht nicht darin, dass sie unmögliche Ziele haben. Es ist nur so, dass er überhaupt keine Ziele hat und überrascht ist, irgendwohin zu kommen.", a:"E. Nightingale"},
  {t:"Wer ein klares Ziel hat, geht voran, auch wenn der Weg schwierig ist. Wer kein Ziel hat, ist verloren, auch wenn der Weg flach ist.", a:"E. Nightingale"},
  {t:"Erfolg ist die fortschreitende Verwirklichung eines erstrebenswerten Ideals. Es ist kein Ziel. Es ist eine Richtung, die über die Zeit hinweg Bestand hat.", a:"E. Nightingale"},
  {t:"Ohne ein definiertes Ziel zu arbeiten kommt dem Rudern am nächsten, ohne zu wissen, welches Ufer man erreichen möchte.", a:"E. Nightingale"},
  {t:"Konformität tötet Potenziale effizienter als jedes äußere Hindernis.", a:"E. Nightingale"},
  {t:"Das zu tun, was alle anderen tun und ein anderes Ergebnis zu erwarten, ist kein Glaube. Es ist Verwirrung.", a:"E. Nightingale"},
  {t:"Der Mensch ist das einzige Lebewesen auf dem Planeten, das bewusst entscheiden kann, was er oder sie wird. Das ist die größte Freiheit, die es gibt, und die, die am wenigsten ausgeübt wird.", a:"E. Nightingale"},
  {t:"Es gibt ein Paradoxon, das nur wenige durchmachen: Wenn man aufhört, sich verzweifelt an das Ergebnis zu klammern, stößt das Ergebnis auf weniger Widerstand.", a:"A. Watts"},
  {t:"Wer dringend Geld braucht, trifft die schlechtesten finanziellen Entscheidungen. Verzweiflung hat den gegenteiligen Effekt von dem, was sie verspricht. Gelassenheit ist der am meisten unterschätzte Wettbewerbsvorteil.", a:"A. Watts"},
  {t:"Ganz in der Gegenwart zu leben bedeutet nicht, die Zukunft zu ignorieren. Es bedeutet zu verstehen, dass die einzige wirkliche Handlung immer im Jetzt stattfindet.", a:"A. Watts"},
  {t:"Der Geist, der nicht still sein kann, kann nicht hören, worauf es ankommt.", a:"A. Watts"},
  {t:"Es gibt einen Unterschied zwischen dem Tun, weil man liebt, was man tut, und dem Tun, um etwas zu erreichen. Der zweite führt fast nie dorthin, wo er versprochen hat.", a:"A. Watts"},
  {t:"Alan Watts fragte: Was würden Sie tun, wenn Geld nicht das Problem wäre? Diese Antwort kommt Ihrem Ziel normalerweise näher als alles, was Sie berechnet haben.", a:"A. Watts"},
  {t:"Das wichtigste Spiel, das Sie spielen können, ist das, das Sie auch dann spielen würden, wenn niemand zuschaut.", a:"A. Watts"},
  {t:"Es gibt Menschen, die auf etwas zulaufen, und Menschen, die vor etwas davonlaufen. Die Richtung ist entgegengesetzt, obwohl die Geschwindigkeit gleich ist.", a:"A. Watts"},
  {t:"Jung hat es auf eine Weise formuliert, die nicht altert: Bis das Unbewusste bewusst wird, wird es weiterhin Ihr Leben lenken und es Schicksal nennen.", a:"C. Jung"},
  {t:"Was Sie bei anderen am meisten ablehnen, ist fast immer das, was Sie bei sich selbst am meisten ablehnen. Der andere ist ein Spiegel, nach dem Sie nicht gefragt haben.", a:"C. Jung"},
  {t:"Der Schatten ist nicht das Schlechte an dir. Es ist alles, was du aus deinem Bewusstsein verbannt hast, weil es dir nicht akzeptabel erschien. Es zu integrieren reift.", a:"C. Jung"},
  {t:"Sie können nicht ändern, was Sie nicht erkennen. Und Sie können nicht erkennen, was Sie bewusst vermeiden.", a:"C. Jung"},
  {t:"Es gibt einen Unterschied zwischen der Maske, die Sie der Welt zeigen, und der Person, die Sie privat sind. Wenn diese Lücke sehr groß ist, sind die psychischen Kosten enorm.", a:"C. Jung"},
  {t:"Der innere Konflikt, den Sie manchmal verspüren, ist kein Symptom dafür, dass etwas nicht stimmt. Es ist das Zeichen dafür, dass sich etwas Wichtiges abzeichnet.", a:"C. Jung"},
  {t:"Sich selbst zu kennen, führt nicht zu Trost. Es führt zu Verantwortung. Und gut übernommene Verantwortung führt zur Freiheit.", a:"C. Jung"},
  {t:"Absicht ist der Samen des Verlangens im Bereich des reinen Bewusstseins. Es ist die Praxis, es klar zu pflanzen und ohne Angst loszulassen.", a:"D. Chopra"},
  {t:"Das Universum wirkt durch dich, nicht für dich. Das verändert die Beziehung zu dem, wonach Sie fragen und wie Sie danach fragen.", a:"D. Chopra"},
  {t:"Synchronizität ist keine Zauberei. Es ist das Ergebnis davon, dass man präsent genug ist, um Verbindungen zu erkennen, die schon immer da waren.", a:"D. Chopra"},
  {t:"Wenn Ihr tiefster Wunsch und Ihre klarste Absicht in Einklang stehen, verschwinden Hindernisse nicht, sondern verändern ihr Ausmaß.", a:"D. Chopra"},
  {t:"Es gibt Menschen, die mit dem Mund fragen und mit ihren Gedanken blockieren. Das stärkste Signal gewinnt immer.", a:"D. Chopra"},
  {t:"Der Körper hört jedem Gespräch zu, das der Geist führt. Was Sie sich im Stillen sagen, hat messbare körperliche Konsequenzen.", a:"D. Chopra"},
  {t:"Gesundheit, geistige Klarheit und Wohlstand sind keine Gegensätze. Sie sind Manifestationen desselben inneren Zustands der Offenheit und Ausrichtung.", a:"D. Chopra"},
  {t:"Man kann aus Mangel nicht geben, ohne sich zu erschöpfen. Man kann nicht aus der Fülle geben, ohne reich zu werden.", a:"D. Chopra"},
  {t:"Das Bewusstsein, das Sie erweitern, während Sie wachsen wollen, beeinflusst alles um Sie herum auf eine Weise, die Sie nie vollständig nachvollziehen können.", a:"D. Chopra"},
  {t:"Jede Entscheidung, die Sie aus Überzeugung treffen, erweitert Ihre Welt. Jede Entscheidung, die aus Angst getroffen wird, zieht sie zusammen.", a:"D. Chopra"},
  {t:"Die ehrlichste Beziehung, die Sie haben können, ist die, die Sie vor dem Schlafengehen mit sich selbst beginnen, wenn niemand sonst im Raum ist.", a:null},
  {t:"Es gibt Menschen, die in Ihr Leben treten, um zu bleiben, Menschen, die eintreten, um es Ihnen beizubringen, und Menschen, die eintreten, um Ihnen zu zeigen, was Sie nicht wollen. Alle drei sind notwendig.", a:null},
  {t:"Die richtige Wahl, mit wem Sie Ihre Zeit verbringen, ist eine Lebensgestaltungsentscheidung, die genauso wichtig ist wie jedes berufliche Ziel.", a:null},
  {t:"Es gibt Menschen, die einen nach jeder Begegnung erschöpfen, und andere, die einen wieder aufladen. Schauen Sie sich an, in welche Kategorie jede Person in Ihrem Leben fällt.", a:null},
  {t:"Die Art und Weise, wie Sie diejenigen behandeln, die Ihnen nichts zurückgeben können, sagt mehr über Ihren Charakter aus als alles, was Sie in der Öffentlichkeit tun.", a:null},
  {t:"Verzeihen bedeutet nicht, das Geschehene zu billigen. Es befreit Sie von der Last, es zu tragen.", a:null},
  {t:"Wirtschaftsfreiheit ist keine Zahl auf einem Konto. Es geht nicht darum, aus der Not heraus Bedingungen akzeptieren zu müssen, die Ihren Werten zuwiderlaufen.", a:null},
  {t:"Es gibt einen Unterschied zwischen einem Job und dem Aufbau einer Karriere. Man gibt einem vorübergehende Sicherheit. Der andere baut dich auf.", a:null},
  {t:"Jede Fähigkeit, die Sie heute entwickeln, ist ein Vermögenswert, den Ihnen keine Wirtschaftskrise nehmen kann.", a:null},
  {t:"Wer sein Wissen diversifiziert, hat mehr Möglichkeiten als jemand, der sich auf ein einzelnes Wissen verlässt.", a:null},
  {t:"Es gibt Menschen, die darauf warten, dass der Markt ihnen Chancen bietet, und Menschen, die die Bedingungen dafür schaffen, dass der Markt sie wahrnimmt.", a:null},
  {t:"Das Einkommen, das Sie heute haben, ist das Ergebnis vergangener Entscheidungen. Welchen Sie in fünf Jahren haben werden, hängt davon ab, welche Sie jetzt nehmen.", a:null},
  {t:"Für andere zu arbeiten kann Teil der Reise sein. Aber wenn es den ganzen Weg geht, bauen Sie den Traum eines anderen auf.", a:null},
  {t:"Wirtschaftliche Unabhängigkeit wird nicht auf einmal erreicht. Es entsteht mit jeder bewussten Entscheidung darüber, wofür Sie Ihre Zeit und Energie investieren.", a:null},
  {t:"Aufgrund dessen, was passiert ist, sind Sie nicht an die Vergangenheit gebunden. Sie sind an die Bedeutung gebunden, die Sie ihr gegeben haben, und entscheiden sich weiterhin dafür, sie festzuhalten.", a:"N. Goddard"},
  {t:"Die Rezension negiert den Schmerz nicht. Es wandelt es in Informationen um und setzt die Energie frei, die der Schmerz verbraucht hat.", a:"N. Goddard"},
  {t:"Jede Nacht, in der Sie sich in einem erhöhten emotionalen Zustand befinden, geben Sie Ihrem Geist, unabhängig davon, wie der Tag verlaufen ist, eine andere Anweisung für morgen.", a:"N. Goddard"},
  {t:"Der Geist lebt in der Gegenwart nicht auf die gleiche Weise wie der Körper. Sie können sich an die Zukunft gewöhnen, bevor sie eintritt. Nutzen Sie das zu Ihrem Vorteil.", a:"N. Goddard"},
  {t:"Was Sie kurz vor dem Schlafengehen spüren, ist die letzte Botschaft, die Sie Ihrem Unterbewusstsein übermitteln, bevor es ohne Ihr Eingreifen funktioniert.", a:"N. Goddard"},
  {t:"Frankl überlebte das Unvorstellbare und kam zu dem Schluss: Wer ein Warum hat, kann fast jedes Wie ertragen.", a:"V. Frankl"},
  {t:"Das Leiden, das einen Namen und eine Adresse hat, ist ein völlig anderes als das, das nicht weiß, wozu es dient.", a:"V. Frankl"},
  {t:"Es gibt eine ultimative Freiheit, die Ihnen nichts und niemand nehmen kann: die Entscheidung, welche innere Position Sie angesichts Ihrer Erfahrungen einnehmen.", a:"V. Frankl"},
  {t:"Das Streben nach Vergnügen führt, wenn es zum primären Ziel wird, genau zum Gegenteil. Vergnügen ist eine Konsequenz, kein Ziel.", a:"V. Frankl"},
  {t:"Die existentielle Leere, die viele Menschen empfinden, ist keine Pathologie. Es ist das Zeichen dafür, dass der Mensch für mehr als nur das Überleben geschaffen wurde.", a:"V. Frankl"},
  {t:"Nicht jede Spannung ist schlecht. Die Spannung zwischen dem, was Sie sind, und dem, was Sie werden können, ist die Ursache für Wachstum.", a:"V. Frankl"},
  {t:"Es liegt eine implizite Verantwortung darin, Talente zu haben. Sie nicht zu nutzen ist keine Demut. Es ist Ausweichen.", a:"V. Frankl"},
  {t:"Der Sinn wird nicht immer gefunden. Manchmal entsteht es schon bei der Entscheidung, wie man auf das, was das Leben präsentiert, reagieren soll.", a:"V. Frankl"},
  {t:"Epictetus wurde als Sklave geboren und lehrte die tiefste Freiheit, die es gibt: die Freiheit, die dir niemand nehmen kann, weil sie in dir lebt.", a:"Epicteto"},
  {t:"Lassen Sie sich nicht durch Dinge beunruhigen, die nicht von Ihnen abhängen. Arbeiten Sie ohne Pause an dem, worauf es ankommt. Diese Unterscheidung ist die Grundlage des Friedens.", a:"Epicteto"},
  {t:"Zu verlangen, dass die Dinge anders werden, als sie sind, ist ein Kampf mit der Realität. Die Realität gewinnt diese Runde immer.", a:"Epicteto"},
  {t:"Die Meinung, die andere über Sie haben, ist ihre. Was du mit deinem Leben machst, gehört dir. Mischen Sie diese Gerichtsbarkeiten nicht.", a:"Epicteto"},
  {t:"Epictetus fragte seine Schüler: Was willst du wirklich? Denn was Sie jeden Tag tun, beantwortet diese Frage bereits.", a:"Epicteto"},
  {t:"Freiheit entsteht nicht dadurch, dass man alles hat, was man will. Es entsteht dadurch, dass man das will, was man hat, und gleichzeitig für das arbeitet, wonach man sucht.", a:"Epicteto"},
  {t:"Der Patient, der über eine Krankheit klagt, verschwendet Energie, die zur Heilung genutzt werden könnte. Das gleiche Prinzip gilt für alle Widrigkeiten.", a:"Epicteto"},
  {t:"Sie können Ereignisse nicht kontrollieren. Ja, Sie können die Interpretation, die Sie ihnen geben, und die entsprechenden Maßnahmen steuern.", a:"Epicteto"},
  {t:"Es liegt eine besondere Würde darin, nicht die Zustimmung anderer zu benötigen, um zu wissen, dass man das Richtige tut.", a:"Epicteto"},
  {t:"Der Gedanke, der dir sagt, dass du nicht genug bist, ist nicht die Wahrheit. Es ist ein Gedanke. Es gibt einen großen Unterschied.", a:"E. Tolle"},
  {t:"Die eigenen Gedanken zu beobachten, ohne sich vollständig mit ihnen zu identifizieren, ist der Beginn innerer Freiheit.", a:"E. Tolle"},
  {t:"Ständiger mentaler Lärm ist nicht der natürliche Zustand des Geistes. Es ist eine Gewohnheit. Und Gewohnheiten werden verändert.", a:"E. Tolle"},
  {t:"Volle Präsenz bei dem, was Sie tun, ist gleichzeitig die produktivste und heiligste Art zu arbeiten.", a:"E. Tolle"},
  {t:"Aus dem Ego heraus zu reagieren ist immer mit Kosten verbunden. Aus der Präsenz heraus zu reagieren, gelingt fast nie.", a:"E. Tolle"},
  {t:"Eine tiefe Akzeptanz dessen, was ist, verhindert nicht, es zu ändern. Paradoxerweise ist es der stärkste Ausgangspunkt für Veränderungen.", a:"E. Tolle"},
  {t:"Tolle beobachtete, dass die Mehrheit nicht erfährt, was mit ihnen passiert. Erleben Sie Ihre Gedanken darüber, was mit Ihnen geschieht. Auf dieser zusätzlichen Schicht lebt unnötiges Leid.", a:"E. Tolle"},
  {t:"Ein Glaube ist keine Tatsache. Es ist eine Hypothese, die Sie so oft wiederholt haben, dass es Ihnen wie eine Tatsache vorkam.", a:null},
  {t:"Die einschränkendsten Überzeugungen sind diejenigen, von denen Sie nicht wissen, dass Sie sie haben, weil Sie sie nie in Frage gestellt haben.", a:null},
  {t:"Fragen Sie sich: „Woher kommt diese Überzeugung?“ kann transformativer sein als jede Motivationstechnik.", a:null},
  {t:"Nicht jede Erbschaft ist Geld oder Eigentum. Wir erben auch Sichtweisen auf die Welt, die das, was wir für möglich halten, einschränken oder erweitern können.", a:null},
  {t:"Die gläserne Decke, die am schwierigsten zu durchbrechen ist, gibt es weder auf dem Markt noch in der Gesellschaft. Es ist im Kopf.", a:null},
  {t:"Ein jahrelang gehegter einschränkender Glaube kann in Sekundenschnelle gelöscht werden, wenn Sie genügend Beweise finden, die ihm widersprechen. Deshalb ist die Suche nach diesen Beweisen so wichtig.", a:null},
  {t:"Es gibt Menschen, die nicht glauben, dass sie echten Wohlstand verdienen. Und sie handeln auf eine Weise, die diesen Glauben bestätigt, ohne zu wissen, dass der Glaube zuerst kam und nicht umgekehrt.", a:null},
  {t:"Was Sie für möglich halten, filtert die Realität, bevor Sie sie erleben. Sie sehen nur das, was Ihr Glaubenssystem Ihnen erlaubt zu sehen.", a:null},
  {t:"Um einen tiefen Glauben zu ändern, ist nicht unbedingt eine jahrelange Therapie erforderlich. Manchmal bedarf es einer einzigen Erfahrung, die stark genug ist, um sie zu ersetzen.", a:null},
  {t:"Der erste Schritt besteht darin, nicht anders zu handeln. Es geht darum, anders zu denken. Die zweite besteht darin, anders zu handeln, um den neuen Gedanken zu bestätigen.", a:null},
  {t:"Aktiv gelebte Dankbarkeit ist keine oberflächliche positive Einstellung. Es ist eine Neuprogrammierung dessen, was der Geist als Priorität registriert.", a:null},
  {t:"Der auf Dankbarkeit trainierte Geist findet Ressourcen, wo der untrainierte Geist nur Mangel findet.", a:null},
  {t:"Für das, was man hat, dankbar zu sein und gleichzeitig für mehr zu arbeiten, ist kein Widerspruch. Es ist der effizienteste Weg, voranzukommen.", a:null},
  {t:"Es gibt einen Unterschied zwischen der Dankbarkeit, sich besser zu fühlen, und der Dankbarkeit, weil man den Wert dessen, was bereits da ist, wirklich erkennt.", a:null},
  {t:"Was Sie heute für selbstverständlich halten, war das, wonach Sie einmal gefragt haben. Nicht zu vergessen: Es verändert die Beziehung zur Gegenwart.", a:null},
  {t:"Gewohnheitsmäßiges Klagen trainiert den Geist, nach dem zu suchen, was fehlt. Gewohnheitsmäßige Dankbarkeit schult sie darin, zu sehen, was ist. Sie entscheiden, welchen Muskel Sie stärken möchten.", a:null},
  {t:"Es muss nicht alles perfekt sein, um etwas Echtes zu finden, für das man dankbar sein kann. Selbst am härtesten Tag funktionierte etwas.", a:null},
  {t:"Die Dankbarkeit, die man im Körper spürt, wird nicht nur mit dem Kopf gedacht, sie hat auch reale Auswirkungen auf den emotionalen Zustand.", a:null},
  {t:"Die Angst vor dem Erfolg ist häufiger als die Angst vor dem Scheitern. Denn Erfolg bringt Verantwortung mit sich, die ein Scheitern nicht hat.", a:null},
  {t:"Es gibt Menschen, die das Gute gerade dann sabotieren, wenn es da ist, weil sie unbewusst damit rechnen, dass etwas schiefgehen wird. Das Erkennen dieses Musters ist der erste Akt der Befreiung.", a:null},
  {t:"Die Angst vor Ablehnung führt dazu, dass Menschen ihre besten Ideen nicht präsentieren, um sich nicht bloßzustellen. Die Welt verliert, was diese Ideen hätten beitragen können.", a:null},
  {t:"Nicht jeder Angst muss man sich sofort stellen. Aber sie alle verdienen es, verstanden zu werden, bevor man ihnen die Entscheidung überlässt.", a:null},
  {t:"Es gibt einen Unterschied zwischen Angst, die Sie vor einer realen Gefahr warnt, und Angst, die Sie aufgrund einer eingebildeten Gefahr einschränkt. Es ist wichtig zu lernen, sie zu unterscheiden.", a:null},
  {t:"Die Angst vor dem Urteil anderer Menschen ist umgekehrt proportional zur Klarheit darüber, wer Sie sind und wohin Sie gehen.", a:null},
  {t:"Nichts macht eine Angst kleiner, als sich ihr zu stellen. Nichts macht es größer, als es zu vermeiden.", a:null},
  {t:"Die Angst, die Sie am meisten lähmt, ist selten die, die Sie benennen. Normalerweise ist es eine Stufe tiefer als diejenige, die es abdeckt.", a:null},
  {t:"Eine Veränderung im Äußeren ohne Veränderung im Inneren führt zu Ergebnissen, die nicht von Dauer sind.", a:null},
  {t:"Wer seine Beziehung zum Scheitern auflöst, scheitert nicht weniger. Lernen Sie schneller.", a:null},
  {t:"Man kann nichts aufbauen, was man nicht mit dem kaputt macht, was nicht mehr nützlich ist. Der Abriss gehört zum Bau.", a:null},
  {t:"Psychische Hygiene ist ebenso notwendig wie körperliche Hygiene. Was man hereinlässt, was man verarbeitet, was man loslässt: Es ist eine tägliche Aufgabe.", a:null},
  {t:"Inneres Wachstum wird selten beworben. Es zeigt sich daran, wie Sie in Momenten reagieren, in denen Sie zuvor auf eine Weise reagiert haben, die Sie in Verlegenheit gebracht hat.", a:null},
  {t:"Alle Weisheit der Welt nützt nichts, wenn sie nicht im konkreten Alltag umgesetzt wird.", a:null},
  {t:"Die Investition in die Selbsterkenntnis ist die einzige Investition, die die Rendite aller anderen steigert.", a:null},
  {t:"Es gibt einen Punkt im persönlichen Wachstum, an dem Sie aufhören, darauf zu warten, dass sich die Welt für Sie verändert, und beginnen, sich selbst zu verändern, damit Sie sich besser in der Welt zurechtfinden können.", a:null},
  {t:"Durch die kontinuierliche Arbeit an etwas Wichtigem lernen Sie mehr über das Leben als durch jedes Buch, auch wenn Bücher hilfreich sind.", a:null},
  {t:"Es gibt eine Weisheit, die nur mit den Händen im Teig erlangt werden kann. Die Theorie ist die Karte, aber das Gebiet kennt man zu Fuß.", a:null},
  {t:"Nur ehrliche Arbeit kann Ihnen etwas über sich selbst beibringen: Wie weit Sie gehen, wenn Sie niemand drängt.", a:null},
  {t:"Exzellenz in jedem Bereich beginnt immer mit der Weigerung, Gutes anzunehmen, wenn Exzellenz möglich ist.", a:null},
  {t:"Die Hingabe, die Sie in das investieren, was Sie tun, ist der ehrlichste Weg, der Welt zu zeigen, wie ernst Sie sich selbst nehmen.", a:null},
  {t:"Nicht jede Arbeit führt zu sofortigen Ergebnissen. Aber jede Arbeit, die ehrlich geleistet wird, bringt Charakter hervor. Und Charakter führt früher oder später zu Ergebnissen.", a:null},
  {t:"Es gibt eine innere Stimme, die weiß, bevor der Verstand die Gründe erkennt. Es ständig zum Schweigen zu bringen ist mit steigenden Kosten verbunden.", a:null},
  {t:"Der Körper sagt die Wahrheit vor dem Geist. Zu lernen, ihm zuzuhören, ist eine Fähigkeit, die Sie vor vielen Fehlern bewahrt.", a:null},
  {t:"Es gibt Zeiten, in denen eine übermäßige Analyse eine Möglichkeit ist, zu vermeiden, was Sie bereits tun müssen.", a:null},
  {t:"Geschulte Intuition und ungebildete Intuition sind verschiedene Dinge. Die erste stammt aus verarbeiteter Erfahrung. Das zweite kann einfach Angst oder ein verstecktes Verlangen sein.", a:null},
  {t:"Um Ihrem Urteil zu vertrauen, müssen Sie nicht immer Recht haben. Es erfordert die Bereitschaft, aus Fehlern zu lernen.", a:null},
  {t:"Es gibt Antworten, die im Stillen erscheinen und niemals im Lärm. Deshalb gehören Momente der Stille zum Entscheidungsprozess.", a:null},
  {t:"Es gibt Menschen, die arbeiten, um ihren Lebensunterhalt zu verdienen, und nicht wirklich wissen, warum sie dieses Leben wollen. Die Frage nach dem Warum ist wichtiger als die Frage nach dem Wie viel.", a:null},
  {t:"Geld ohne Zweck ist Lärm. Geld im Dienste von etwas Wichtigem ist Verstärker.", a:null},
  {t:"Mehr zu geben, als man bekommt, ist keine Naivität. Es handelt sich um eine langfristige Strategie, für deren Umsetzung fast niemand die Geduld aufbringt.", a:null},
  {t:"Der Ruf, den Sie durch ständige außergewöhnliche Arbeit aufbauen, ist mehr wert als jede Marketingkampagne.", a:null},
  {t:"Der Preis, den Sie für Ihre Arbeit akzeptieren, ist das erste Signal, das Sie dem Markt darüber geben, wie sehr Sie Ihre Arbeit schätzen.", a:null},
  {t:"Mit Integrität zu arbeiten, obwohl es einfacher ist, dies nicht zu tun, ist die praktischste Definition von professionellem Charakter.", a:null},
  {t:"Was hätten Sie am liebsten getan, wenn Sie auf Ihr Leben in zwanzig Jahren blicken?", a:null},
  {t:"Wann haben Sie das letzte Mal etwas zum ersten Mal gemacht?", a:null},
  {t:"Nach welchem ​​internen Gespräch leben Sie? Treibt Sie dieses Gespräch an oder hält es Sie zurück?", a:null},
  {t:"Welchen Teil Ihres aktuellen Lebens haben Sie aktiv konstruiert und welchen Teil haben Sie einfach akzeptiert, weil er so war, wie er war?", a:null},
  {t:"Lebst du dein Leben oder die Version deines Lebens, die andere von dir erwartet haben?", a:null},
  {t:"Was wäre, wenn das, was Ihnen Ihrer Meinung nach fehlt, von vornherein keine Bedingung, sondern eine Ausrede wäre?", a:null},
  {t:"Wem würdest du die Richtung deines Lebens geben, wenn du könntest? Und wenn die Antwort nicht Sie sind, warum nicht?", a:null},
  {t:"Was ist Ihnen wirklich wichtig, wenn Sie alles herausnehmen, was Ihnen wichtig sein sollte?", a:null},
  {t:"Wie anders würde Ihr Leben aussehen, wenn Sie davon ausgehen würden, dass Sie genau das verdienen, was Sie wollen?", a:null},
  {t:"Was würden Sie heute aufgeben, wenn Sie wüssten, dass Sie keine Zukunft haben?", a:null},
  {t:"Was ist der Unterschied zwischen dem Leben, das Sie beschreiben, wenn jemand Sie fragt, wie es Ihnen geht, und dem, das Sie tatsächlich führen?", a:null},
  {t:"Was müssen Sie sich verzeihen, um ohne diese Last voranzukommen?", a:null},
  {t:"Es gibt einen Unterschied zwischen dem Scheitern einer Sache und dem Scheitern. Das eine ist ein Ereignis. Das andere ist eine Identität, die Sie annehmen möchten.", a:null},
  {t:"Jede Person, die Sie bewundern konnten, hat eine Reihe von Fehlern, die sie selten zeigt. Sichtbarer Erfolg beruht auf unsichtbaren Fehlern.", a:null},
  {t:"Auch der Fehler, den Sie nicht in Netzwerken veröffentlichen, zählt. Manchmal auch mehr, weil man es privat und ohne Anhörung bearbeitet hat.", a:null},
  {t:"Schnelles Scheitern und schnelles Lernen ist eine Strategie. Langsames Scheitern und Nichtlernen sind Kosten, die sich nicht lohnen.", a:null},
  {t:"Nicht alles, was nicht funktionierte, war ein Fehler. Manche Dinge waren einfach nicht so, und man musste sie durchgehen, um es zu erkennen.", a:null},
  {t:"Ein Scheitern, bei dem man sich fragt, was man anders machen kann, ist wertvoll. Derjenige, bei dem man sich nur fragt, was mit der Welt nicht stimmt, ist es nicht.", a:null},
  {t:"Fehlertoleranz bedeutet nicht, dass man sich nicht um das Ergebnis kümmert. Das bedeutet, dass das Ergebnis nicht Ihren Wert als Person definiert.", a:null},
  {t:"Es gibt Menschen, die vergangene Misserfolge als Grund nutzen, es in der Gegenwart nicht zu versuchen. Das bedeutet, der Vergangenheit Macht über die Zukunft zu geben, die ihr nicht gehört.", a:null},
  {t:"Fülle häuft sich nicht grenzenlos an. Es geht darum, mehr als genug von dem zu haben, was wirklich wichtig ist.", a:null},
  {t:"Es gibt Menschen, die viel haben und in innerer Knappheit leben. Es gibt Menschen, die wenig haben und im Überfluss leben. Der interne Zustand wartet nicht auf äußere Bedingungen.", a:null},
  {t:"Die Knappheitsmentalität konkurriert um Ressourcen, die ihrer Meinung nach begrenzt sind. Der Überfluss schafft sie dort, wo sie vorher nicht existierten.", a:null},
  {t:"Was Sie wirklich geben, ohne die Rendite zu berechnen, kommt auf eine Weise zurück, die Sie nicht vorhersagen können und die über die ursprüngliche Berechnung hinausgeht.", a:null},
  {t:"Es gibt eine Art von Reichtum, die in keiner Bilanz auftaucht: die Gewissheit, dass man nach seinen Werten lebt.", a:null},
  {t:"Wer weiß, dass er überall Werte schaffen kann, ist nie wirklich ohne Ressourcen.", a:null},
  {t:"Ein Mangel an Zeit, Geld oder Energie hat fast immer einen Mangel an Klarheit darüber zur Folge, worauf es wirklich ankommt.", a:null},
  {t:"Alles, wonach Sie im Außen suchen, ist eine projizierte Version von etwas, das im Inneren bereits existiert.", a:null},
  {t:"Der Moment, der ein Leben definiert, weist selten darauf hin, dass es dieser Moment ist. Deshalb verdient jede Entscheidung Ernsthaftigkeit.", a:null},
  {t:"Weisheit ist nicht die Anhäufung von Wissen. Es geht darum zu wissen, wann und wie man das wenige, was man wirklich verstanden hat, anwenden kann.", a:null},
  {t:"Es gibt eine Lebensweise, bei der nicht alles in Ordnung sein muss, um in Ordnung zu sein. Diesen Weg zu finden ist die Suche.", a:null},
  {t:"Das Schwierigste für Sie, loszulassen, ist fast immer das Schwierigste für Sie, zuzugeben, dass es Ihnen nicht mehr dient.", a:null},
  {t:"Das Leben, das Sie nicht in Frage stellen, ist das Leben, das andere für Sie entworfen haben.", a:null},
  {t:"Jede wirkliche Transformation beginnt in einem Moment, der von außen gewöhnlich erscheint.", a:null},
  {t:"Es gibt keine Abkürzungen zu Dingen, die sich lohnen. Es gibt intelligentere Wege, aber alle müssen beschritten werden.", a:null},
  {t:"Heute könnte genau der Tag sein, der in der Zukunft alles definiert, was danach kommt. Unterschätze es nicht.", a:null},
  {t:"Die Entscheidung, weiter zu glauben, auch wenn die Beweise noch nicht vorliegen, ist die ehrlichste Definition von Glauben.", a:null}
];
